        public MultiDeviceDetails(List<DisplayDevice> ConnectedDevices, bool bIsVirtualBattery, List<DisplayDevice> USBDeviceList = null)
        {
            try
            {
                InitializeComponent();

                IsVirtualBattery = bIsVirtualBattery;
                IsPageFirstTimeLoading = true;
                _ConnectedDevices = ConnectedDevices;
                _USBDeviceList = USBDeviceList;
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        protected override void OnAppearing()
        {
            base.OnAppearing();

            if (MainActivity.MainActivityInstance != null)
            {
                MainActivity.MainActivityInstance.ApplyStatusBarStyle();
            }

            RemoteSessionDetails._remote = App.Services.GetService<RemoteSessionService>();
            RemoteSessionDetails._remote.OnReceive += MultiDeviceReceive;

            Task.Run(() => CheckRemoteSessionPingStatus());

            _ = Dispatcher.DispatchAsync(async () =>
            {
                InitializeGaugePointers();
                await Initialization();
            });
        }
        private async Task Initialization()
        {
            try
            {
                await ShowBusyindicatior(true);

                #region Binding
                SFKViewModel.virualBatteryList = new ObservableCollection<VirualBattery>();
                SFKViewModel.virualBatteryList.Add(new VirualBattery { Name = "Select virtual battery" });

                ddlvirtualbattry.BindingContext = SFKViewModel;
                ddlvirtualbattry.ItemsSource = SFKViewModel.virualBatteryList;
                ddlvirtualbattry.DisplayMemberPath = "Name";

                ddlvirtualbattry.SelectedIndex = 0;
                ddlvirtualbattry.SelectedValue = "Select Virtual battery";
                IsBusyIndicatorForReconnecing.IsVisible = false;

                for (int i = 0; i < _ObjBLEDevices.Length; i++)
                {
                    _ObjBLEDevices[i] = new BLEDevice();
                    _ListMultiDeviceArrResBytes.Add(new List<byte[]>());
                    _ListMultiDeviceArr04ResBytes.Add(new List<byte[]>());
                    _ReadOnlyOncesForDevices[i] = true;
                    UsedNewFirmwareDevices[i] = false;
                    CounterFor09Command[i] = 0;
                    _ObjstackSelectedDevices.Add(new StackLayout());
                    bSameCell[i] = true;
                }

                _IsCommunicateWithUSB = _ConnectedDevices == null && _USBDeviceList != null;
                BmsDeviceCount = _IsCommunicateWithUSB ? _USBDeviceList.Count : _ConnectedDevices.Count;

                await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.GetProtocolType, null);

                ResponceCount = 0;
                while (ResponceCount < 40)
                {
                    await Task.Delay(1000);
                    if (_ObjDeviceInformations[BmsDeviceCount - 1] != null && _ObjDeviceInformations[BmsDeviceCount - 1].CustomCollectionHeatingPadTimer != null && _ObjDeviceInformations[BmsDeviceCount - 1].CustomCollectionHeatingPadTimer.Count() > 0)
                    {
                        break;
                    }
                    if (ResponceCount == 20)
                    {
                        await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.GetProtocolType, null);
                    }
                    ResponceCount++;
                }

                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    string rawName = _IsCommunicateWithUSB ? _USBDeviceList[i].DeviceName : _ConnectedDevices[i].DeviceName;

                    BLEDeviceName[i] = Regex.Replace(rawName?.ToLower().Trim() ?? "", "[^0-9a-zA-Z:,]+", "");
                }

                switchGraph.IsOn = false;

                MultiGraph.IsVisible = true;
                CombineGraph.IsVisible = false;

                _ObjReadValues = new ValidReadValues();

                objMultiDeviceViewModel.arrTotalAmps = new decimal[BmsDeviceCount];
                objMultiDeviceViewModel.arrTotalVoltes = new decimal[BmsDeviceCount];
                objMultiDeviceViewModel.arrTotalWatts = new decimal[BmsDeviceCount];
                objMultiDeviceViewModel.arrTotalSOC = new double[BmsDeviceCount];
                objMultiDeviceViewModel.arrFirmwareVersion = new double[BmsDeviceCount];
                objMultiDeviceViewModel.arrCaseTemp1 = new decimal[BmsDeviceCount];
                objMultiDeviceViewModel.arrCaseTemp2 = new decimal[BmsDeviceCount];

                _ObjBatteryData = new BattetryData();

                SFKViewModel.virualBatteryList = new ObservableCollection<VirualBattery>();
                MultiSKFTabView.IsVisible = true;

                MultiSKFTabView.SelectedIndex = 1;
                Main.ImageSource = "homeiconselect.png";

                if (_ObjDeviceInformations[0] != null)
                {
                    rangesliderAmpsDraw.BindingContext = _ObjDeviceInformations[0];
                    rangesliderAmpsDraw.Minimum = _ObjDeviceInformations[0].CustomCollectionAmpsDraw[0].Value;
                    rangesliderAmpsDraw.Maximum = _ObjDeviceInformations[0].CustomCollectionAmpsDraw[_ObjDeviceInformations[0].CustomCollectionAmpsDraw.Count - 1].Value;

                    rangesliderVoltsDraw.BindingContext = _ObjDeviceInformations[0];
                    rangesliderVoltsDraw.Minimum = _ObjDeviceInformations[0].CustomCollectionVoltsDraw[0].Value;
                    rangesliderVoltsDraw.Maximum = _ObjDeviceInformations[0].CustomCollectionVoltsDraw[_ObjDeviceInformations[0].CustomCollectionVoltsDraw.Count - 1].Value;

                    is24vBattery = _ObjDeviceInformations[0].Is24VBattery;

                    for (int i = 0; i < BmsDeviceCount; i++)
                    {
                        if (_ObjDeviceInformations[i] != null)
                        {
                            stackOverAmpTimeOutOuter.IsVisible = true;
                            if (!_ObjDeviceInformations[i].OverAmpTimeOut)
                            {
                                stackOverAmpTimeOutOuter.IsVisible = false;
                                break;
                            }
                        }
                    }
                }

                if (is24vBattery)
                {
                    if (BmsDeviceCount >= 3)
                    {
                        StackSwitchBetweenGraph.IsVisible = StackSwitchBetweenGraph.IsEnabled = false;
                    }
                }

                if (BmsDeviceCount > 4)
                {
                    StackSwitchBetweenGraph.IsVisible = false;
                }

                nWriteCounter = 0;

                await Task.WhenAll(
                           PopulateAboutTabAsync(),

                           DisplayChart(),

                           LoadBattreySetupPage(),

                           AutoDashBoardBindings()
                 );

                await ShowBusyindicatior(true);

                OnSizeAllocated(DeviceWidth, DeviceHeight);

                #endregion Binding

                await StartExecution();
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task StartExecution()
        {
            _Executioncts = new CancellationTokenSource();

            await btnPullRequestRead();
            RunMainPageWhileLoop = true;
            var tasks = Enumerable.Range(0, BmsDeviceCount)
                .Select(async i =>
                {
                    int staggerDelay = (PullingRequestTime * i) / BmsDeviceCount;

                    await Task.Delay(staggerDelay, _Executioncts.Token);

                    _Executioncts.Token.ThrowIfCancellationRequested();

                    await HandleDevice(i);
                });

            await Task.WhenAll(tasks);
        }
        public async void MultiDeviceReceive(string fromDevice, string Datatype, string jsondata)
        {
            try
            {
                nWriteCounter = 0;
                if (Datatype == RemoteSessionReceiveDataTypes.byteCommand.ToString())
                {
                    var payload = Serializer.Deserialize<string>(jsondata).Split('^');
                    if (payload.Length < 2)
                        return;

                    var byteArr = Serializer.Deserialize<byte[]>(payload[0]);
                    var modelIndex = Serializer.Deserialize<int>(payload[1]);

                    Func<byte[], Task>[] dispatch =
                    {
                        bytes => FirstDeviceReceiveBytes(bytes),
                        bytes => SecoundDeviceReceiveBytes(bytes),
                        bytes => ThirdDeviceReceiveBytes(bytes),
                        bytes => FourthDeviceReceiveBytes(bytes),
                        bytes => FifthDeviceReceiveBytes(bytes),
                        bytes => SixthDeviceReceiveBytes(bytes),
                        bytes => SeventhDeviceReceiveBytes(bytes),
                        bytes => EighthDeviceReceiveBytes(bytes)
                    };

                    if ((uint)modelIndex >= dispatch.Length)
                        return;

                    await MainThread.InvokeOnMainThreadAsync(() => dispatch[modelIndex](byteArr));
                }
                else if (Datatype == RemoteSessionReceiveDataTypes.DeviceConnectionStatus.ToString())
                {
                    IsDeviceConnectionStatus = false;
                    IsDeviceConnectionStatus = Serializer.Deserialize<bool>(jsondata);
                }
                else if (Datatype == RemoteSessionReceiveDataTypes.ReEstablishConnection.ToString())
                {
                    string strRecconection = Serializer.Deserialize<string>(jsondata);
                    bool ProccedforReconnect = false;
                    string strDeviceName = string.Empty;
                    if (strRecconection.Contains("|"))
                    {
                        ProccedforReconnect = Convert.ToBoolean(strRecconection.Split('|')[0]);
                        strDeviceName = Convert.ToString(strRecconection.Split('|')[1]);
                    }
                    else
                    {
                        ProccedforReconnect = Convert.ToBoolean(strRecconection);
                    }

                    MainThread.InvokeOnMainThreadAsync(async () =>
                    {
                        await ReEstablishConnection(ProccedforReconnect, strDeviceName);
                    });
                }
                else if (Datatype == RemoteSessionReceiveDataTypes.ProtocolType.ToString())
                {
                    bool[] _IsSFKH2Devices = Serializer.Deserialize<bool[]>(jsondata);

                    for (int i = 0; i < BmsDeviceCount; i++)
                    {
                        string rawName = _ConnectedDevices[i].DeviceName;

                        BLEDeviceName[i] = Regex.Replace(rawName?.ToLower().Trim() ?? "", "[^0-9a-zA-Z:,]+", "");

                        if (!string.IsNullOrEmpty(BLEDeviceName[i]))
                        {
                            _ObjDeviceInformations[i] = await DeviceDefaultValues.GetDeviceData(BLEDeviceName[i]);

                            _IsSFKH2Device[i] = _IsSFKH2Devices[i];

                            if (_ObjDeviceInformations[i] != null)
                            {
                                _ObjProtocols[i] = await DeviceDefaultValues.GetProtocolDetails(_IsCommunicateWithUSB ? "SFKV1" : _IsSFKH2Device[i] ? "SFKV4" : "SFKV1");
                            }
                        }
                    }
                }
                else if (Datatype == RemoteSessionReceiveDataTypes.RemoteSessionEnd.ToString())
                {
                    string data = Serializer.Deserialize<string>(jsondata);
                    if (data == "CONNECTION_LOST")
                    {
                        await RemoteConnectionLost(false);
                    }
                    else
                    {
                        RemoteSessionDetails.CustomerName = data;
                        await StopRemoteSession();
                    }
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task PopulateAboutTabAsync()
        {

            if ((_ConnectedDevices != null || _USBDeviceList != null) && _ObjDeviceInformations[0] != null)
            {
                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    string? MacAddress = _ConnectedDevices[i].MacAddress;

                    string model = _ObjDeviceInformations[i]?.ModelName ?? "";

                    switch (i)
                    {
                        case 0: lblMacAddressID1.Text = MacAddress; lblAboutModelName1.Text = lblAboutModelNameInner1.Text = model; break;
                        case 1: lblMacAddressID2.Text = MacAddress; lblAboutModelName2.Text = lblAboutModelNameInner2.Text = model; break;
                        case 2: lblMacAddressID3.Text = MacAddress; lblAboutModelName3.Text = lblAboutModelNameInner3.Text = model; stkDevice3.IsVisible = true; break;
                        case 3: lblMacAddressID4.Text = MacAddress; lblAboutModelName4.Text = lblAboutModelNameInner4.Text = model; stkDevice4.IsVisible = true; break;
                        case 4: lblMacAddressID5.Text = MacAddress; lblAboutModelName5.Text = lblAboutModelNameInner5.Text = model; stkDevice5.IsVisible = true; break;
                        case 5: lblMacAddressID6.Text = MacAddress; lblAboutModelName6.Text = lblAboutModelNameInner6.Text = model; stkDevice6.IsVisible = true; break;
                        case 6: lblMacAddressID7.Text = MacAddress; lblAboutModelName7.Text = lblAboutModelNameInner7.Text = model; stkDevice7.IsVisible = true; break;
                    }
                }
            }
        }
