        private async Task RebindModel(int ModelIndex, bool AssignMultiGraph = true, bool AssignSingleGraph = false)
        {
            try
            {
                if (AssignMultiGraph)
                {
                    if (ModelIndex == 0)
                    {
                        if (is24vBattery)
                        {
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "1", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "2", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "3", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "4", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "5", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "6", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "7", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "8", CellVolts = 0.0M });
                        }
                        else
                        {
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "1", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "2", CellVolts = 0.0M });
                            _ObjBatteryData.BData1.Add(new CellInfo { CellName = "3", CellVolts = 0.0M });
