                {
                    gaugeTempDeviceOneScale.Maximum = gaugeTempDeviceTwoScale.Maximum = gaugeTempDeviceThreeScale.Maximum = gaugeTempDeviceFourScale.Maximum = 140;
                }
                else
                {
