        }
        private async void MultiSKFTabView_SelectionChanged(object sender, Syncfusion.Maui.TabView.TabSelectionChangedEventArgs e)
        {
            try
            {
                await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.TabSwitch, e.NewIndex);

                #region Color

                Scan.ImageSource = "scanicon.png";
                Main.ImageSource = "homeicon.png";
                Details.ImageSource = "detailsicon.png";
                Tools.ImageSource = "toolicon.png";
                Auto.ImageSource = "autoicon.png";
                About.ImageSource = "abouticon.png";

                Scan.TextColor = Color.FromHex("#000");
                Main.TextColor = Color.FromHex("#000");
                Details.TextColor = Color.FromHex("#000");
                Tools.TextColor = Color.FromHex("#000");
                About.TextColor = Color.FromHex("#000");
                Auto.TextColor = Color.FromHex("#000");

                StopTracking();
                if (e.NewIndex != 4)
                {
                    ShowAbsoluteLayout(false, "", true);
                }

                #endregion Color

                if (e.NewIndex == 0)
                {
                    IsScantabSelect = true;
                    Scan.ImageSource = "scaniconselect.png";
                    Scan.TextColor = Color.FromHex("#f0c000");

                    await ShowDisplayPopup("Alert", "Going back to the scan screen will disconnect the Bluetooth connection from the current battery, are you sure you want to proceed?");
                }
                else if (e.NewIndex == 1)
                {
                    Main.ImageSource = "homeiconselect.png";
                    Main.TextColor = Color.FromHex("#f0c000");

                    await OnHomeTabLoad();
                }
                else if (e.NewIndex == 2)
                {
                    if (FirstTimeDetailLoad)
                    {
                        await ShowBusyindicatior(true);
                        FirstTimeDetailLoad = false;
                    }

                    Details.ImageSource = "detailsiconselect.png";
                    Details.TextColor = Color.FromHex("#f0c000");
                }
                else if (e.NewIndex == 3)
                {
                    Auto.ImageSource = "autoiconselect.png";
                    Auto.TextColor = Color.FromHex("#f0c000");

                    if (BmsDeviceCount > 4)
                    {
                        await ShowDisplayPopup("Information", "Auto Dashboard is only available on 4 or less Devices.");
                        IsScantabSelect = true;
                    }

                    await CheckAndRequestLocationPermission();
                }
                else if (e.NewIndex == 4)
                {
                    Tools.ImageSource = "tooliconselect.png";
                    Tools.TextColor = Color.FromHex("#f0c000");

                    await LoadToolTabForReadingData();
                }
                else if (e.NewIndex == 5)
                {
                    About.ImageSource = "abouticonselect.png";
                    About.TextColor = Color.FromHex("#f0c000");
                }
            }
            catch (Exception ex)
            {
                //New Added
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task OnHomeTabLoad()
        {
            try
            {
                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    if (UsedNewFirmwareDevices[i])
                    {
                        await ReadSOCAndHeatingMode(i);
                    }

                    if (_IsSFKH2Device[i])
                    {
                        await ReadH2ParameterValues(i);
                    }
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task UpdateIconBlink(int ModelIndex)
        {
            try
            {
                SetUpdateIconVisible(ModelIndex, true);
                await Task.Delay(500);
                SetUpdateIconVisible(ModelIndex, false);
            }
            catch (Exception ex)
            {
            }
        }
        private async Task HandleDevice(int i)
        {
            try
            {
                _ObjBLEDevices[i].DeviceName = _ConnectedDevices[i].DeviceName;

                while (RunMainPageWhileLoop)
                {
                    UpdateIconBlink(i);

                    if (MultiSKFTabView.SelectedIndex == 1 || MultiSKFTabView.SelectedIndex == 3)
                    {
                        await ReadBMSDetails03Command(i);

                        await Task.Delay(100);
                    }

                    if (MultiSKFTabView.SelectedIndex == 2)
                    {
                        await ReadCellCount04Command(i);

                        await Task.Delay(100);
                    }

                    if (_ReadOnlyOncesForDevices[i])
                    {
                        _ReadOnlyOncesForDevices[i] = false;

                        await ReadBMSCodeWith0ACommand(i);

                        await btnTemperatureUnitRead();

                        await ReadSOCAndHeatingMode(i);

                        await Task.Delay(100);

                        for (int k = 0; k < 3; k++)
                        {
                            await ChargingUnderTempRead(i, RegisterEnum.REG_CHGUT);

                            await Task.Delay(200);

                            if (_ObjBLEDevices[i].LowTempValue > decimal.Zero) { break; }
                        }

                        await Task.Delay(100);

                        if (_IsSFKH2Device[i])
                        {
                            await ReadBatteryType(i);

                            await Task.Delay(100);

                            for (int k = 0; k < 3; k++)
                            {
                                await ReadH2ParameterValues(i);

                                await Task.Delay(200);

                                if (_ObjBLEDevices[i].IsChargePulseOn || _ObjBLEDevices[i].IsHighSOCMonitorOn) { break; }
                            }

                            await Task.Delay(100);

                            await ReadDaySinceFullCharge(i);

                            await Task.Delay(100);

                            await ReadDaySinceFullCharge(i, "date");

                            SinceFullCharge(i);
                        }

                        await LoadToolTabForReadingData();

                        GetSerialNumberFromBMS(i);

                        if (UsedNewFirmwareDevices[i])
                        {
                            for (int j = 0; j < 3; j++)
                            {
                                await ReadSOCAndHeatingMode(i);

                                await Task.Delay(200);

                                if (_ObjBLEDevices[i].HeatingStartTempValue > decimal.Zero)
                                {
                                    break;
                                }
                            }

                            if (_ObjBLEDevices.Take(BmsDeviceCount).All(m => m.SocMaxValue > 0) && _ObjBLEDevices.Take(BmsDeviceCount).Any(m => m.SocMaxValue < 100))
                            {
                                ShowDisplayPopup("Warning", "Maximum SOC below 100% should only be used if batteries are in storage and not actively being used.");
                            }
                        }
                    }

                    if (MultiSKFTabView.SelectedIndex == 1 && _ObjBLEDevices[i].BatteryType == 2 && _IsSFKH2Device[i] && UsedNewFirmwareDevices[i] && CounterFor09Command[i] >= 15)
                    {
                        await ReadSOCAndHeatingMode(i);
                        CounterFor09Command[i] = 0;
                    }

                    if (MultiSKFTabView.SelectedIndex == 1 && _IsSFKH2Device[i] && CounterForFullyChargedDateCommand[i] >= 30)
                    {
                        await ReadDaySinceFullCharge(i);

                        await Task.Delay(50);

                        await ReadDaySinceFullCharge(i, "date");

                        CounterForFullyChargedDateCommand[i] = 0;
                    }

                    await Displaydata(_ObjBLEDevices[i], i);

                    if (nWriteCounter >= EstablishConnectionDatAttemps)
                    {
                        await ShowDisplayPopup("Error", "Unable to connect.");
                        RemoteSessionDetails._remote.OnReceive -= MultiDeviceReceive;
                        await Task.Delay(10000);

                        MainPage Page = new MainPage(false);
                        await Navigation.PushAsync(Page);
                    }

                    CounterFor09Command[i] = CounterFor09Command[i] + PullingRequestTime / 1000;
                    CounterForFullyChargedDateCommand[i] = CounterForFullyChargedDateCommand[i] + PullingRequestTime / 1000;
                    await Task.Delay(PullingRequestTime);
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                    nWriteCounter++;
            }
        }
        private void SetUpdateIconVisible(int index, bool isVisible)
        {
            switch (index)
            {
                case 0: imgUpdateIconForDevice1.IsVisible = isVisible; break;
                case 1: imgUpdateIconForDevice2.IsVisible = isVisible; break;
                case 2: imgUpdateIconForDevice3.IsVisible = isVisible; break;
                case 3: imgUpdateIconForDevice4.IsVisible = isVisible; break;
                case 4: imgUpdateIconForDevice5.IsVisible = isVisible; break;
                case 5: imgUpdateIconForDevice6.IsVisible = isVisible; break;
                case 6: imgUpdateIconForDevice6.IsVisible = isVisible; break;
                case 7: imgUpdateIconForDevice7.IsVisible = isVisible; break;
            }
        }
        private async Task FirstDeviceReceiveBytes(byte[] receivedBytes, bool ReceiveCommandByUSb = false)
        {
            try
            {
                if (receivedBytes != null && ((byte[])receivedBytes).Length > 1)
                {
                    if (await VerifyByteUsingChecksum(receivedBytes))
                    {
                        if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "241"))
                        {
                            if (receivedBytes.Count() > 5)
                            {
                                int iDays = 0;
                                iDays = ((byte[])receivedBytes)[3];

                                _ObjReadValues.DaySinceFullCharge = iDays;

                                if (iDays >= 0 && iDays <= 7)
                                {
                                    frmSinceFullCharge1.BackgroundColor = Color.FromHex("#14B729");
                                }
                                else if (iDays >= 8 && iDays <= 15)
                                {
                                    frmSinceFullCharge1.BackgroundColor = Color.FromHex("#F0C000");
                                }
                                else if (iDays >= 15 && iDays <= 22)
                                {
                                    frmSinceFullCharge1.BackgroundColor = Color.FromHex("#F99C00");
                                }
                                else if (iDays >= 23)
                                {
                                    frmSinceFullCharge1.BackgroundColor = Color.FromHex("#DC2624");
                                }

                                lblSinceFullCharge1.Text = Convert.ToString(iDays);
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "199"))
                        {
                            if (receivedBytes.Count() > 7)
                            {
                                string sFullChargeDate = string.Empty;

                                string year = ((byte[])receivedBytes)[3].ToString("X").PadLeft(2, '0') + ((byte[])receivedBytes)[4].ToString("X").PadLeft(2, '0');
                                string month = ((byte[])receivedBytes)[5].ToString("X").PadLeft(2, '0');
                                string day = ((byte[])receivedBytes)[6].ToString("X").PadLeft(2, '0');

                                sFullChargeDate = Convert.ToString(Convert.ToInt32(year, 16)) + "/" + Convert.ToString(Convert.ToInt32(month, 16)) + "/" + Convert.ToString(Convert.ToInt32(day, 16));

                                if (Convert.ToInt32(year, 16) > 0 && Convert.ToInt32(month, 16) > 0 && Convert.ToInt32(day, 16) > 0)
                                {
                                    strFullyChargedDate[0] = sFullChargeDate;
                                }
                                else
                                {
                                    strFullyChargedDate[0] = "N/A";
                                    lblSinceFullCharge1.Text = "?";
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "249"))
                        {
                            _ObjBLEDevices[0].BatteryType = Convert.ToInt32(((byte[])receivedBytes)[3].ToString(), 16);
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "232"))
                        {
                            if (((byte[])receivedBytes)[0].ToString() == "204" && ((byte[])receivedBytes)[receivedBytes.Length - 1].ToString() == "207")
                            {
                                string hex = BitConverter.ToString(receivedBytes);
                                string[] subs = hex.Split('-');

                                if (subs.Length > 25)
                                {
                                    int CurrentBattType = Convert.ToInt32(subs[25]);
                                    _ObjBLEDevices[0].BatteryType = CurrentBattType;
                                }

                                if (_ObjBLEDevices[0].BatteryType == 2)
                                {
                                    if (subs.Length > 14)
                                    {
                                        bool IsHighSOCMonitorOn = false;
                                        if (subs[14] == "01" || subs[14] == "1")
                                        {
                                            IsHighSOCMonitorOn = true;
                                        }
                                        _ObjBLEDevices[0].IsHighSOCMonitorOn = IsHighSOCMonitorOn;

                                        if (IsHighSOCMonitorOn)
                                        {
                                            imgHomeMaxSOC1.Source = "regulatehighsoc.png";
                                        }
                                        else
                                        {
                                            imgHomeMaxSOC1.Source = "socupperlimit.png";
                                        }
                                    }
                                }
                                else
                                {
                                    imgHomeMaxSOC1.Source = "socupperlimit.png";
                                }

                                if (_ObjBLEDevices[0].BatteryType == 2)
                                {
                                    if (subs.Length > 19)
                                    {
                                        bool IsChargePulseOn = false;
                                        if (subs[18] == "01" || subs[18] == "1")
                                        {
                                            IsChargePulseOn = true;
                                        }
                                        _ObjBLEDevices[0].IsChargingOn = IsChargePulseOn;

                                        int ChargePulseHR = 0;
                                        if (IsChargePulseOn)
                                        {
                                            // Charge Pulse Hours
                                            ChargePulseHR = Convert.ToInt32(subs[19], 16);
                                        }

                                        if (IsChargePulseOn && ChargePulseHR > 0)
                                        {
                                            imgHomeMinSOC1.Source = "chargepulsealerts.png";
                                        }
                                        else
                                        {
                                            imgHomeMinSOC1.Source = "soclowerlimit.png";
                                        }
                                    }
                                }
                                else
                                {
                                    imgHomeMinSOC1.Source = "soclowerlimit.png";
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && ((byte[])receivedBytes)[1].ToString() == "3" || ((byte[])receivedBytes)[1].ToString() == "03")
                        {
                            _ListMultiDeviceArrResBytes[0].Clear();
                            if (_ListMultiDeviceArrResBytes[0].Count() == 0)
                            {
                                _ListMultiDeviceArrResBytes[0].Add(receivedBytes);
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && (((byte[])receivedBytes)[1].ToString() == "10"))
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                UsedNewFirmwareDevices[0] = true;
                                lblMCUID1.Text = "";
                                for (int i = 4; i < receivedBytes.Count() - 3; i++)
                                {
                                    lblMCUID1.Text += Convert.ToString(receivedBytes[i]);
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && ((byte[])receivedBytes)[1].ToString() == "9" || ((byte[])receivedBytes)[1].ToString() == "09")
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                string hex = BitConverter.ToString(receivedBytes);
                                string[] subs = hex.Split('-');                            

                                if (subs != null)
                                {
                                    //HeatingStartTemp  - 10 C 
                                    string temp1Vhex = subs[5] + subs[6];
                                    int int_temp1Avalue = Convert.ToInt32(temp1Vhex, 16);
                                    decimal dec_temp1 = ((decimal)int_temp1Avalue / 10) - 273.15M;
                                    _ObjBLEDevices[0].HeatingStartTempValue = dec_temp1;
                                    int intTempValue = Convert.ToInt32(dec_temp1);

                                    if (Tempmap.ContainsKey(intTempValue))
                                    {
                                        int value = IsFahrenheit ? Tempmap[intTempValue] : intTempValue;
                                        string unit = IsFahrenheit ? "°F" : "°C";

                                        lblHeatingMode1.Text = value.ToString() + unit;
                                        TempsliderLowTempValue = value;
                                    }

                                    //HeatingStopTemp   - 15 C
                                    string temp2Vhex = subs[7] + subs[8];
                                    int int_temp2Avalue = Convert.ToInt32(temp2Vhex, 16);
                                    decimal dec_temp2 = ((decimal)int_temp2Avalue / 10) - 273.15M;
                                    _ObjBLEDevices[0].HeatingStopTempValue = dec_temp2;

                                    //HeatingMode  -  2 Mode

                                    int Mode = Convert.ToInt32(subs[9], 16);
                                    if (Mode == 1 || Mode == 01)
                                    {
                                        _ObjBLEDevices[0].HeatingMode = "L";
                                    }
                                    else if (Mode == 2 || Mode == 02)
                                    {
                                        _ObjBLEDevices[0].HeatingMode = "S";
                                    }
                                    else if (Mode == 0 || Mode == 00)
                                    {
                                        _ObjBLEDevices[0].HeatingMode = "D";
                                    }

                                    _ObjBLEDevices[0].HeatingModeValue = Mode;

                                    // Soc Protection Bit -  01 
                                    _ObjBLEDevices[0].SocProtectionBitValue = Convert.ToInt32(subs[10], 16);

                                    //Soc Max Value -  95% 
                                    _ObjBLEDevices[0].SocMaxValue = Convert.ToInt32(subs[11], 16);

                                    //Soc Min Value  -  50%   
                                    _ObjBLEDevices[0].SocMinValue = Convert.ToInt32(subs[12], 16);

                                    if (_ObjBLEDevices[0].HeatingModeValue == 2)
                                    {
                                        int value = IsFahrenheit ? Tempmap[intTempValue] : intTempValue;
                                        string unit = IsFahrenheit ? "°F" : "°C";

                                        lblHeatingMode1.Text = value.ToString() + unit;
                                    }
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && (((byte[])receivedBytes)[1].ToString() == "162"))
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                _ObjBLEDevices[0].BarcodeValue = string.Empty;
                                for (int i = 5; i < ((byte[])receivedBytes).Length - 3; i++)
                                {
                                    _ObjBLEDevices[0].BarcodeValue += Convert.ToChar(((byte[])receivedBytes)[i]);
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && (((byte[])receivedBytes)[1].ToString() == "4" || ((byte[])receivedBytes)[1].ToString() == "04"))
                        {
                            try
                            {
                                int Count = Convert.ToInt32((((byte[])receivedBytes)[2].ToString("X") + ((byte[])receivedBytes)[3].ToString("X")), 16) / 2;
                                BatteryCellCount = Convert.ToInt32((((byte[])receivedBytes)[2].ToString("X") + ((byte[])receivedBytes)[3].ToString("X")), 16) / 2;
                                if (Count >= 8)
                                {
                                    _ListMultiDeviceArr04ResBytes[0].Clear();
                                    if (_ListMultiDeviceArr04ResBytes[0].Count == 0)
                                    {
                                        _ListMultiDeviceArr04ResBytes[0].Add(receivedBytes);
                                    }
                                }
                                else
                                {
                                    byte[] data = receivedBytes;
                                    string hex = BitConverter.ToString(data);
                                    string[] subs = hex.Split('-');
                                    //declaring a variable and assigning hex value
                                    if (subs != null && subs.Length > 0 && data[0].ToString() == "221")
                                    {
                                        int SumOfByte = 0;
                                        for (int i = 2; i < (subs.Count() - 3); i++)
                                        {
                                            SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                        }
                                        string CheckSum = (65536 - SumOfByte).ToString("X");
                                        if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
