                                                            imgFirstWarningForDevice1.Source = "cellovervolt.png";
                                                            lblFirstWarningForDevice1.Text = "Cell \novervolt";
                                                        }
                                                        else
                                                        {
                                                            FirstWarningForDevice1.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 1)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FirstWarningForDevice1.IsVisible = true;
                                                            imgFirstWarningForDevice1.Source = "cellundervolt.png";
                                                            lblFirstWarningForDevice1.Text = "Cell \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!FirstWarningForDevice1.IsVisible)
                                                            {
                                                                FirstWarningForDevice1.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 2)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice1.IsVisible = true;
                                                            imgSecoundWarningForDevice1.Source = "packovervolt.png";
                                                            lblSecoundWarningForDevice1.Text = "Pack \novervolt";
                                                        }
                                                        else
                                                        {
                                                            SecoundWarningForDevice1.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 3)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice1.IsVisible = true;
                                                            imgSecoundWarningForDevice1.Source = "packundervolt.png";
                                                            lblSecoundWarningForDevice1.Text = "Pack \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!SecoundWarningForDevice1.IsVisible)
