                                                        if (bits[i] == 1)
                                                        {
                                                            ThirdWarningForDevice1.IsVisible = true;
                                                            imgThirdWarningForDevice1.Source = "chargeundertemp.png";
                                                            lblThirdWarningForDevice1.Text = "Charge \nundertemp";

                                                            if (!UsedNewFirmwareDevices[0])
                                                            {
                                                                if (_ObjDeviceInformations[0].HeatingPadWarning)
