                                                            imgFourthWarningForDevice1.Source = "dischargeovertemp.png";
                                                            lblFourthWarningForDevice1.Text = "Discharge \novertemp";
                                                        }
                                                        else
                                                        {
                                                            FourthWarningForDevice1.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 7)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FourthWarningForDevice1.IsVisible = true;
                                                            imgFourthWarningForDevice1.Source = "dischargeundertemp.png";
                                                            lblFourthWarningForDevice1.Text = "Discharge \nundertemp";
                                                        }
                                                        else
                                                        {
                                                            if (!FourthWarningForDevice1.IsVisible)
