                                                if (!SecoundWarningForDevice1.IsVisible && !ThirdWarningForDevice1.IsVisible && !FourthWarningForDevice1.IsVisible && !FifthWarningForDevice1.IsVisible && !SixthWarningForDevice1.IsVisible && !SeventhWarningForDevice1.IsVisible && !EightWarningForDevice1.IsVisible && !NinethWarningForDevice1.IsVisible && !TenthWarningForDevice1.IsVisible)
                                                {
