                                                    imgFirstWarningForDevice1.Source = "normalcell.png";
                                                    lblFirstWarningForDevice1.Text = "Normal";
                                                }
                                            }
                                            catch
                                            {
                                                SecoundWarningForDevice1.IsVisible = ThirdWarningForDevice1.IsVisible = FourthWarningForDevice1.IsVisible = FifthWarningForDevice1.IsVisible = SixthWarningForDevice1.IsVisible = SeventhWarningForDevice1.IsVisible = EightWarningForDevice1.IsVisible = false;

                                                FirstWarningForDevice1.IsVisible = true;

                                                imgFirstWarningForDevice1.Source = "normalcell.png";
                                                lblFirstWarningForDevice1.Text = "Normal";
                                            }
                                        }

                                        int firstbatterystatuspercent = 0;

                                        //FirmwareVeriosn
                                        if (subs.Length > 22)
                                        {
                                            double veriosn = Convert.ToDouble(subs[22]);
                                            _ObjBLEDevices[0].FirmwareVeriosn = Math.Round(veriosn / 10, 1);
                                            if (_ObjBLEDevices[0].FirmwareVeriosn >= 6.4)
                                            {
                                                UsedNewFirmwareDevices[0] = true;
                                            }
                                        }

                                        //SOC
                                        if (subs.Length > 23)
                                        {
                                            firstbatterystatuspercent = Convert.ToInt32(subs[23], 16);
                                            _ObjBLEDevices[0].SOC = firstbatterystatuspercent + "% SOC";
                                        }
                                    }
                                    else
                                    {
                                        _ListMultiDeviceArrResBytes[0].Clear();
                                        await CheckSumFailer(0);
                                    }
                                }
                            }
                        }
                        else if (iFirstByteInner == 4)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {
                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                //declaring a variable and assigning hex value
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        if (subs.Length > 4)
                                        {
                                            string cellCount = subs[2] + subs[3];
                                            int ncellCount = Convert.ToInt32(cellCount, 16);
                                            ncellCount = ncellCount / 2;

                                            List<TempCellInfo> _Bdata1 = _ObjBatteryData.BData1.Select(item => new TempCellInfo { cellvolts = item.CellVolts }).ToList();

                                            if (!bSameCell[0])
                                            {
                                                _ObjBatteryData.BData1 = new ObservableCollection<CellInfo>();
                                                await RebindModel(0);
                                            }

                                            if (ncellCount > 0)
                                            {
                                                for (int i = 0; i < ncellCount; i++)
                                                {
                                                    int ntemp = (i * 2) + 4;

                                                    string hex_value = subs[ntemp] + subs[ntemp + 1];

                                                    //converting hex to integer
                                                    int int_value = Convert.ToInt32(hex_value, 16);

                                                    decimal dcellvolts = ((decimal)int_value / 1000.00M);
                                                    if (dcellvolts >= (decimal)1.5 && dcellvolts <= (decimal)4.5)
                                                    {
                                                        int SingleGraphcellNumber = 0;
                                                        if (i == 0)
                                                        {
                                                            SingleGraphcellNumber = 0;
                                                        }
                                                        else if (i == 1)
                                                        {
                                                            SingleGraphcellNumber = 1;
                                                        }
                                                        else if (i == 2)
                                                        {
                                                            SingleGraphcellNumber = 2;
                                                        }
                                                        else if (i == 3)
                                                        {
                                                            SingleGraphcellNumber = 3;
                                                        }
                                                        else if (i == 4)
                                                        {
                                                            SingleGraphcellNumber = 4;
                                                        }
                                                        else if (i == 5)
                                                        {
                                                            SingleGraphcellNumber = 5;
                                                        }
                                                        else if (i == 6)
                                                        {
                                                            SingleGraphcellNumber = 6;
                                                        }
                                                        else if (i == 7)
                                                        {
                                                            SingleGraphcellNumber = 7;
                                                        }

                                                        _ObjBatteryData.BData1[i].CellVolts = Math.Round(dcellvolts, 2);
                                                        _ObjBatteryData.SingleGraphBattery[SingleGraphcellNumber].Cell = Math.Round(dcellvolts, 2);

                                                        if (dcellvolts >= 0 && dcellvolts <= 2.749M)
                                                        {
                                                            _ObjBatteryData.Battery1Colors[i] = Colors.Red;
                                                            _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Red;
                                                        }
                                                        else if (dcellvolts >= 2.750M && dcellvolts <= 2.999M)
                                                        {
                                                            _ObjBatteryData.Battery1Colors[i] = Colors.Orange;
                                                            _ObjBatteryData.Battery1TextColors[i] = Colors.Black;
                                                            _ObjBatteryData.SingleGraphTextColor[SingleGraphcellNumber] = Colors.Black;
                                                            _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Orange;
                                                        }
                                                        else if (dcellvolts >= 3M && dcellvolts <= 3.099M)
                                                        {
                                                            _ObjBatteryData.Battery1Colors[i] = Colors.Yellow;
                                                            _ObjBatteryData.Battery1TextColors[i] = Colors.Black;
                                                            _ObjBatteryData.SingleGraphTextColor[SingleGraphcellNumber] = Colors.Black;
                                                            _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Yellow;
                                                        }
                                                        else if (dcellvolts >= 3.1M && dcellvolts <= 4M)
                                                        {
                                                            _ObjBatteryData.Battery1Colors[i] = Colors.Green;
                                                            _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Green;
                                                        }
                                                        else
                                                        {
                                                            _ObjBatteryData.Battery1Colors[i] = Colors.Green;
                                                            _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Green;
                                                        }
                                                    }
                                                }

                                                chartItemSourceFirstBattery.ItemsSource = _ObjBatteryData.BData1;
                                                chartItemSourceFirstBattery.PaletteBrushes = _ObjBatteryData.Battery1Colors;

                                                for (int i = 0; i < _ObjBatteryData.BData1.Count(); i++)
                                                {
                                                    if (_ObjBatteryData.BData1[i].CellVolts == _Bdata1[i].cellvolts)
                                                    {
                                                        bSameCell[0] = true;
                                                    }
                                                    else
                                                    {
                                                        bSameCell[0] = false;
                                                    }
                                                }
                                            }
                                        }
                                    }
                                    else
                                    {
                                        _ListMultiDeviceArr04ResBytes[0].Clear();
                                        await CheckSumFailer(0);
                                    }
                                }
                            }
                        }
                    }
                    else
                    {
                        await CheckSumFailer(0);
                    }
                }
            }
            catch (Exception ex)
            {

            }
        }
        private async Task SecoundDeviceReceiveBytes(byte[] receivedBytes, bool ReceiveCommandByUSb = false)
        {
            try
            {
                if (receivedBytes != null && ((byte[])receivedBytes).Length > 1)
                {
                    if (await VerifyByteUsingChecksum(receivedBytes))
                    {
                        if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "241"))
                        {
                            if (receivedBytes.Count() > 5)
                            {
                                int iDays = 0;
                                iDays = ((byte[])receivedBytes)[3];

                                _ObjReadValues.DaySinceFullCharge = iDays;

                                if (iDays >= 0 && iDays <= 7)
                                {
                                    frmSinceFullCharge2.BackgroundColor = Color.FromHex("#14B729");
                                }
                                else if (iDays >= 8 && iDays <= 15)
                                {
                                    frmSinceFullCharge2.BackgroundColor = Color.FromHex("#F0C000");
                                }
                                else if (iDays >= 15 && iDays <= 22)
                                {
                                    frmSinceFullCharge2.BackgroundColor = Color.FromHex("#F99C00");
                                }
                                else if (iDays >= 23)
                                {
                                    frmSinceFullCharge2.BackgroundColor = Color.FromHex("#DC2624");
                                }

                                lblSinceFullCharge2.Text = Convert.ToString(iDays);
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "199"))
                        {
                            if (receivedBytes.Count() > 7)
                            {
                                string sFullChargeDate = string.Empty;

                                string year = ((byte[])receivedBytes)[3].ToString("X").PadLeft(2, '0') + ((byte[])receivedBytes)[4].ToString("X").PadLeft(2, '0');
                                string month = ((byte[])receivedBytes)[5].ToString("X").PadLeft(2, '0');
                                string day = ((byte[])receivedBytes)[6].ToString("X").PadLeft(2, '0');

                                sFullChargeDate = Convert.ToString(Convert.ToInt32(year, 16)) + "/" + Convert.ToString(Convert.ToInt32(month, 16)) + "/" + Convert.ToString(Convert.ToInt32(day, 16));

                                if (Convert.ToInt32(year, 16) > 0 && Convert.ToInt32(month, 16) > 0 && Convert.ToInt32(day, 16) > 0)
                                {
                                    strFullyChargedDate[1] = sFullChargeDate;
                                }
                                else
                                {
                                    strFullyChargedDate[1] = "N/A";
                                    lblSinceFullCharge2.Text = "?";
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "249"))
                        {
                            _ObjBLEDevices[1].BatteryType = Convert.ToInt32(((byte[])receivedBytes)[3].ToString(), 16);
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "232"))
                        {
                            if (((byte[])receivedBytes)[0].ToString() == "204" && ((byte[])receivedBytes)[receivedBytes.Length - 1].ToString() == "207")
                            {
                                string hex = BitConverter.ToString(receivedBytes);
                                string[] subs = hex.Split('-');

                                if (subs.Length > 25)
                                {
                                    int CurrentBattType = Convert.ToInt32(subs[25]);
                                    _ObjBLEDevices[1].BatteryType = CurrentBattType;
                                }

                                if (_ObjBLEDevices[1].BatteryType == 2)
                                {
                                    if (subs.Length > 14)
                                    {
                                        bool IsHighSOCMonitorOn = false;
                                        if (subs[14] == "01" || subs[14] == "1")
                                        {
                                            IsHighSOCMonitorOn = true;
                                        }
                                        _ObjBLEDevices[1].IsHighSOCMonitorOn = IsHighSOCMonitorOn;

                                        if (IsHighSOCMonitorOn)
                                        {
                                            imgHomeMaxSOC2.Source = "regulatehighsoc.png";
                                        }
                                        else
                                        {
                                            imgHomeMaxSOC2.Source = "socupperlimit.png";
                                        }
                                    }
                                }
                                else
                                {
                                    imgHomeMaxSOC2.Source = "socupperlimit.png";
                                }

                                if (_ObjBLEDevices[1].BatteryType == 2)
                                {
                                    if (subs.Length > 19)
                                    {
                                        bool IsChargePulseOn = false;
                                        if (subs[18] == "01" || subs[18] == "1")
                                        {
                                            IsChargePulseOn = true;
                                        }
                                        _ObjBLEDevices[1].IsChargingOn = IsChargePulseOn;

                                        int ChargePulseHR = 0;
                                        if (IsChargePulseOn)
                                        {
                                            // Charge Pulse Hours
                                            ChargePulseHR = Convert.ToInt32(subs[19], 16);
                                        }

                                        if (IsChargePulseOn && ChargePulseHR > 0)
                                        {
                                            imgHomeMinSOC2.Source = "chargepulsealerts.png";
                                        }
                                        else
                                        {
                                            imgHomeMinSOC2.Source = "soclowerlimit.png";
                                        }
                                    }
                                }
                                else
                                {
                                    imgHomeMinSOC2.Source = "soclowerlimit.png";
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && ((byte[])receivedBytes)[1].ToString() == "3" || ((byte[])receivedBytes)[1].ToString() == "03")
                        {
                            _ListMultiDeviceArrResBytes[1].Clear();
                            if (_ListMultiDeviceArrResBytes[1].Count() == 0)
                            {
                                _ListMultiDeviceArrResBytes[1].Add(receivedBytes);
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && (((byte[])receivedBytes)[1].ToString() == "10"))
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                UsedNewFirmwareDevices[1] = true;
                                lblMCUID2.Text = "";
                                for (int i = 4; i < receivedBytes.Count() - 3; i++)
                                {
                                    lblMCUID2.Text += Convert.ToString(receivedBytes[i]);
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && ((byte[])receivedBytes)[1].ToString() == "9" || ((byte[])receivedBytes)[1].ToString() == "09")
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                string hex = BitConverter.ToString(receivedBytes);
                                string[] subs = hex.Split('-');
                                if (subs != null)
                                {
                                    //HeatingStartTemp  - 10 C 
                                    string temp1Vhex = subs[5] + subs[6];
                                    int int_temp1Avalue = Convert.ToInt32(temp1Vhex, 16);
                                    decimal dec_temp1 = ((decimal)int_temp1Avalue / 10) - 273.15M;
                                    _ObjBLEDevices[1].HeatingStartTempValue = dec_temp1;

                                    int intTempValue = Convert.ToInt32(dec_temp1);

                                    if (Tempmap.ContainsKey(intTempValue))
                                    {
                                        int value = IsFahrenheit ? Tempmap[intTempValue] : intTempValue;
                                        string unit = IsFahrenheit ? "°F" : "°C";

                                        lblHeatingMode2.Text = value.ToString() + unit;
                                        TempsliderLowTempValue = value;
                                    }

                                    //HeatingStopTemp   - 15 C
                                    string temp2Vhex = subs[7] + subs[8];
                                    int int_temp2Avalue = Convert.ToInt32(temp2Vhex, 16);
                                    decimal dec_temp2 = ((decimal)int_temp2Avalue / 10) - 273.15M;
                                    _ObjBLEDevices[1].HeatingStopTempValue = dec_temp2;

                                    //HeatingMode  -  2 Mode

                                    int Mode = Convert.ToInt32(subs[9], 16);
                                    if (Mode == 1 || Mode == 01)
                                    {
                                        _ObjBLEDevices[1].HeatingMode = "L";
                                    }
                                    else if (Mode == 2 || Mode == 02)
                                    {
                                        _ObjBLEDevices[1].HeatingMode = "S";
                                    }
                                    else if (Mode == 0 || Mode == 00)
                                    {
                                        _ObjBLEDevices[1].HeatingMode = "D";
                                    }

                                    _ObjBLEDevices[1].HeatingModeValue = Mode;

                                    // Soc Protection Bit -  01 
                                    _ObjBLEDevices[1].SocProtectionBitValue = Convert.ToInt32(subs[10], 16);

                                    //Soc Max Value -  95% 
                                    _ObjBLEDevices[1].SocMaxValue = Convert.ToInt32(subs[11], 16);

                                    //Soc Min Value  -  50%   
                                    _ObjBLEDevices[1].SocMinValue = Convert.ToInt32(subs[12], 16);

                                    if (_ObjBLEDevices[1].HeatingModeValue == 2)
                                    {
                                        int value = IsFahrenheit ? Tempmap[intTempValue] : intTempValue;
                                        string unit = IsFahrenheit ? "°F" : "°C";

                                        lblHeatingMode2.Text = value.ToString() + unit;
                                    }
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "221" && (((byte[])receivedBytes)[1].ToString() == "162"))
                        {
                            if (((byte[])receivedBytes).Length > 7)
                            {
                                _ObjBLEDevices[1].BarcodeValue = string.Empty;
