                                                {
                                                    //charging chalu                                                                                                                    
                                                    _ObjBLEDevices[1].IsChargingOn = true;
                                                }
                                                else
                                                {
                                                    //charging bandh                                                                                                                    
                                                    _ObjBLEDevices[1].IsChargingOn = false;
                                                }
                                            }
                                        }

                                        //BMS Error
                                        if (subs.Length > 21)
                                        {
                                            byte[] byteArray = new byte[2];

                                            try
                                            {
                                                string sprotectionStatus = subs[20] + subs[21];
                                                int protectionStatus1 = Convert.ToInt32(sprotectionStatus, 16);

                                                List<int> bits = new List<int>();
                                                for (int i = 0; i <= 15; i++)
                                                {
                                                    bits.Add(((int)((protectionStatus1 >> i) & 0x01)));
                                                }

                                                for (int i = 0; i < 15; i++)
                                                {
                                                    if (i == 0)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FirstWarningForDevice2.IsVisible = true;
                                                            imgFirstWarningForDevice2.Source = "cellovervolt.png";
                                                            lblFirstWarningForDevice2.Text = "Cell \novervolt";
                                                        }
                                                        else
                                                        {
                                                            FirstWarningForDevice2.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 1)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FirstWarningForDevice2.IsVisible = true;
                                                            imgFirstWarningForDevice2.Source = "cellundervolt.png";
                                                            lblFirstWarningForDevice2.Text = "Cell \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!FirstWarningForDevice2.IsVisible)
                                                            {
                                                                FirstWarningForDevice2.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 2)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice2.IsVisible = true;
                                                            imgSecoundWarningForDevice2.Source = "packovervolt.png";
                                                            lblSecoundWarningForDevice2.Text = "Pack \novervolt";
                                                        }
                                                        else
                                                        {
                                                            SecoundWarningForDevice2.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 3)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice2.IsVisible = true;
                                                            imgSecoundWarningForDevice2.Source = "packundervolt.png";
                                                            lblSecoundWarningForDevice2.Text = "Pack \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!SecoundWarningForDevice2.IsVisible)
                                                            {
                                                                SecoundWarningForDevice2.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 4)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            ThirdWarningForDevice2.IsVisible = true;
                                                            imgThirdWarningForDevice2.Source = "chargeovertemp.png";
                                                            lblThirdWarningForDevice2.Text = "Charge \novertemp";
                                                        }
                                                        else
                                                        {
                                                            ThirdWarningForDevice2.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 5)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            ThirdWarningForDevice2.IsVisible = true;
                                                            imgThirdWarningForDevice2.Source = "chargeundertemp.png";
                                                            lblThirdWarningForDevice2.Text = "Charge \nundertemp";
                                                            if (!UsedNewFirmwareDevices[1])
                                                            {
                                                                if (_ObjDeviceInformations[1].HeatingPadWarning)
                                                                {
                                                                    NinethWarningForDevice2.IsVisible = true;

                                                                    imgNinethWarningForDevice2.Source = "heatingpadson.png";
                                                                    lblNinethWarningForDevice2.Text = "Heating on";
                                                                }
                                                            }
                                                        }
                                                        else
                                                        {
                                                            if (!ThirdWarningForDevice2.IsVisible)
                                                            {
                                                                ThirdWarningForDevice2.IsVisible = false;
                                                                if (!UsedNewFirmwareDevices[1])
                                                                {
                                                                    NinethWarningForDevice2.IsVisible = false;
                                                                }
                                                            }
                                                        }
                                                    }
                                                    else if (i == 6)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FourthWarningForDevice2.IsVisible = true;
                                                            imgFourthWarningForDevice2.Source = "dischargeovertemp.png";
                                                            lblFourthWarningForDevice2.Text = "Discharge \novertemp";
                                                        }
                                                        else
                                                        {
                                                            FourthWarningForDevice2.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 7)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FourthWarningForDevice2.IsVisible = true;
                                                            imgFourthWarningForDevice2.Source = "dischargeundertemp.png";
                                                            lblFourthWarningForDevice2.Text = "Discharge \nundertemp";
                                                        }
                                                        else
                                                        {
                                                            if (!FourthWarningForDevice2.IsVisible)
                                                            {
                                                                FourthWarningForDevice2.IsVisible = false;
                                                            }
                                                        }
