                                }
                            }
                        }
                        else if (iFirstByteInner == 4)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {
                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                //declaring a variable and assigning hex value
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        if (subs.Length > 4)
                                        {
                                            try
                                            {
                                                List<TempCellInfo> _Bdata3 = _ObjBatteryData.BData3.Select(item => new TempCellInfo { cellvolts = item.CellVolts }).ToList();

                                                if (!bSameCell[2])
                                                {
                                                    _ObjBatteryData.BData3 = new ObservableCollection<CellInfo>();
                                                    await RebindModel(2);
                                                }

                                                string cellCount = subs[2] + subs[3];
                                                int ncellCount = Convert.ToInt32(cellCount, 16);
                                                ncellCount = ncellCount / 2;
                                                if (ncellCount > 0)
                                                {
                                                    //SeriesColors.Clear();
                                                    for (int i = 0; i < ncellCount; i++)
                                                    {
                                                        int ntemp = (i * 2) + 4;

                                                        string hex_value = subs[ntemp] + subs[ntemp + 1];

                                                        //converting hex to integer
                                                        int int_value = Convert.ToInt32(hex_value, 16);

                                                        decimal dcellvolts = ((decimal)int_value / 1000.00M);

                                                        if (dcellvolts >= (decimal)1.5 && dcellvolts <= (decimal)4.5)
                                                        {
                                                            int SingleGraphcellNumber = 0;
                                                            if (i == 0)
                                                            {
                                                                SingleGraphcellNumber = 16;
                                                            }
                                                            else if (i == 1)
                                                            {
                                                                SingleGraphcellNumber = 17;
                                                            }
                                                            else if (i == 2)
                                                            {
                                                                SingleGraphcellNumber = 18;
                                                            }
                                                            else if (i == 3)
                                                            {
                                                                SingleGraphcellNumber = 19;
                                                            }
                                                            else if (i == 4)
                                                            {
                                                                SingleGraphcellNumber = 20;
                                                            }
                                                            else if (i == 5)
                                                            {
                                                                SingleGraphcellNumber = 21;
                                                            }
                                                            else if (i == 6)
                                                            {
                                                                SingleGraphcellNumber = 22;
                                                            }
                                                            else if (i == 7)
                                                            {
                                                                SingleGraphcellNumber = 23;
                                                            }

                                                            _ObjBatteryData.BData3[i].CellVolts = Math.Round(dcellvolts, 2);
                                                            _ObjBatteryData.SingleGraphBattery[SingleGraphcellNumber].Cell = Math.Round(dcellvolts, 2);

                                                            if (dcellvolts >= 0 && dcellvolts <= 2.749M)
                                                            {
                                                                _ObjBatteryData.Battery3Colors[i] = Colors.Red;
                                                                _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Red;
                                                            }
                                                            else if (dcellvolts >= 2.750M && dcellvolts <= 2.999M)
                                                            {
                                                                _ObjBatteryData.Battery3Colors[i] = Colors.Orange;
                                                                _ObjBatteryData.Battery3TextColors[i] = Colors.Black;
                                                                _ObjBatteryData.SingleGraphTextColor[SingleGraphcellNumber] = Colors.Black;
                                                                _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Orange;
                                                            }
                                                            else if (dcellvolts >= 3M && dcellvolts <= 3.099M)
                                                            {
                                                                _ObjBatteryData.Battery3Colors[i] = Colors.Yellow;
                                                                _ObjBatteryData.Battery3TextColors[i] = Colors.Black;
                                                                _ObjBatteryData.SingleGraphTextColor[SingleGraphcellNumber] = Colors.Black;
                                                                _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Yellow;
                                                            }
                                                            else if (dcellvolts >= 3.1M && dcellvolts <= 4M)
                                                            {
                                                                _ObjBatteryData.Battery3Colors[i] = Colors.Green;
                                                                _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Green;
                                                            }
                                                            else
                                                            {
                                                                _ObjBatteryData.Battery3Colors[i] = Colors.Green;
                                                                _ObjBatteryData.SingleGraphCellColor[SingleGraphcellNumber] = Colors.Green;
                                                            }
                                                        }
                                                    }

                                                    chartItemSourceThirdBattery.ItemsSource = _ObjBatteryData.BData3;
                                                    chartItemSourceThirdBattery.PaletteBrushes = _ObjBatteryData.Battery3Colors;

                                                    for (int i = 0; i < _ObjBatteryData.BData3.Count(); i++)
                                                    {
                                                        if (_ObjBatteryData.BData3[i].CellVolts == _Bdata3[i].cellvolts)
                                                        {
                                                            bSameCell[2] = true;
                                                        }
                                                        else
                                                        {
                                                            bSameCell[2] = false;
                                                        }
                                                    }


                                                    if (BmsDeviceCount == 3)
                                                    {
                                                        await ShowBusyindicatior(false);
