                                                if (!SecoundWarningForDevice4.IsVisible && !ThirdWarningForDevice4.IsVisible && !FourthWarningForDevice4.IsVisible && !FifthWarningForDevice4.IsVisible && !SixthWarningForDevice4.IsVisible && !SeventhWarningForDevice4.IsVisible && !EightWarningForDevice4.IsVisible && !NinethWarningForDevice4.IsVisible && !TenthWarningForDevice4.IsVisible)
