                                            string temp1Vhex = subs[27] + subs[28];
                                            int int_temp1Avalue = Convert.ToInt32(temp1Vhex, 16);
                                            decimal dec_temp1 = ((decimal)int_temp1Avalue / 10) - 273.15M;
                                            if (IsFahrenheit)
