                                                            imgSecoundWarningForDevice5.Source = "packovervolt.png";
                                                            lblSecoundWarningForDevice5.Text = "Pack \novervolt";
                                                        }
                                                        else
                                                        {
                                                            SecoundWarningForDevice5.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 3)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice5.IsVisible = true;
                                                            imgSecoundWarningForDevice5.Source = "packundervolt.png";
                                                            lblSecoundWarningForDevice5.Text = "Pack \nundervolt";
                                                        }
