                                                if (!SecoundWarningForDevice5.IsVisible && !ThirdWarningForDevice5.IsVisible && !FourthWarningForDevice5.IsVisible && !FifthWarningForDevice5.IsVisible && !SixthWarningForDevice5.IsVisible && !SeventhWarningForDevice5.IsVisible && !EightWarningForDevice5.IsVisible)
