                            }
                        }
                        else if (iFirstByteInner == 4)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {
                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                //declaring a variable and assigning hex value
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        if (subs.Length > 4)
                                        {
                                            try
                                            {
                                                List<TempCellInfo> _Bdata5 = _ObjBatteryData.BData5.Select(item => new TempCellInfo { cellvolts = item.CellVolts }).ToList();

                                                if (!bSameCell[4])
                                                {
                                                    _ObjBatteryData.BData5 = new ObservableCollection<CellInfo>();
                                                    await RebindModel(4);
                                                }

                                                string cellCount = subs[2] + subs[3];
                                                int ncellCount = Convert.ToInt32(cellCount, 16);
                                                ncellCount = ncellCount / 2;
                                                if (ncellCount > 0)
                                                {
                                                    //SeriesColors.Clear();
                                                    for (int i = 0; i < ncellCount; i++)
                                                    {
                                                        int ntemp = (i * 2) + 4;

                                                        string hex_value = subs[ntemp] + subs[ntemp + 1];

                                                        //converting hex to integer
                                                        int int_value = Convert.ToInt32(hex_value, 16);

                                                        decimal dcellvolts = ((decimal)int_value / 1000.00M);
                                                        if (dcellvolts >= (decimal)1.5 && dcellvolts <= (decimal)4.5)
                                                        {
                                                            _ObjBatteryData.BData5[i].CellVolts = Math.Round(dcellvolts, 2);

                                                            if (dcellvolts >= 0 && dcellvolts <= 2.749M)
                                                            {
                                                                _ObjBatteryData.Battery5Colors[i] = Colors.Red;
                                                            }
                                                            else if (dcellvolts >= 2.750M && dcellvolts <= 2.999M)
                                                            {
                                                                _ObjBatteryData.Battery5Colors[i] = Colors.Orange;
                                                                _ObjBatteryData.Battery5TextColors[i] = Colors.Black;
                                                            }
                                                            else if (dcellvolts >= 3M && dcellvolts <= 3.099M)
                                                            {
                                                                _ObjBatteryData.Battery5Colors[i] = Colors.Yellow;
                                                                _ObjBatteryData.Battery5TextColors[i] = Colors.Black;
                                                            }
                                                            else if (dcellvolts >= 3.1M && dcellvolts <= 4M)
                                                            {
                                                                _ObjBatteryData.Battery5Colors[i] = Colors.Green;
                                                            }
                                                            else
                                                            {
                                                                _ObjBatteryData.Battery5Colors[i] = Colors.Green;
                                                            }
                                                        }
                                                    }

                                                    chartItemSourceFifthBattery.ItemsSource = _ObjBatteryData.BData5;
                                                    chartItemSourceFifthBattery.PaletteBrushes = _ObjBatteryData.Battery5Colors;

                                                    for (int i = 0; i < _ObjBatteryData.BData5.Count(); i++)
                                                    {
                                                        if (_ObjBatteryData.BData5[i].CellVolts == _Bdata5[i].cellvolts)
                                                        {
                                                            bSameCell[4] = true;
                                                        }
                                                        else
                                                        {
                                                            bSameCell[4] = false;
                                                        }
                                                    }

                                                    if (BmsDeviceCount == 5)
                                                    {
                                                        await ShowBusyindicatior(false);
                                                    }
                                                }
                                            }
                                            catch { }
                                        }
                                    }
                                    else
                                    {
                                        _ListMultiDeviceArr04ResBytes[4].Clear();
                                        await CheckSumFailer(4);
                                    }
                                }
                            }
                        }
                    }
                    else
                    {
                        await CheckSumFailer(4);
                    }
                }
            }
            catch (Exception ex)
            {

            }
        }
        private async Task SixthDeviceReceiveBytes(byte[] receivedBytes, bool ReceiveCommandByUSb = false)
        {
            try
            {
                if (receivedBytes != null && ((byte[])receivedBytes).Length > 1)
                {
                    if (await VerifyByteUsingChecksum(receivedBytes))
                    {
                        if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "241"))
                        {
                            if (receivedBytes.Count() > 5)
                            {
                                int iDays = 0;
                                iDays = ((byte[])receivedBytes)[3];

                                _ObjReadValues.DaySinceFullCharge = iDays;

                                if (iDays >= 0 && iDays <= 7)
                                {
                                    frmSinceFullCharge6.BackgroundColor = Color.FromHex("#14B729");
                                }
                                else if (iDays >= 8 && iDays <= 15)
                                {
                                    frmSinceFullCharge6.BackgroundColor = Color.FromHex("#F0C000");
                                }
                                else if (iDays >= 15 && iDays <= 22)
                                {
                                    frmSinceFullCharge6.BackgroundColor = Color.FromHex("#F99C00");
                                }
                                else if (iDays >= 23)
                                {
                                    frmSinceFullCharge6.BackgroundColor = Color.FromHex("#DC2624");
                                }

                                lblSinceFullCharge6.Text = Convert.ToString(iDays);
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "199"))
                        {
                            if (receivedBytes.Count() > 7)
                            {
                                string sFullChargeDate = string.Empty;

                                string year = ((byte[])receivedBytes)[3].ToString("X").PadLeft(2, '0') + ((byte[])receivedBytes)[4].ToString("X").PadLeft(2, '0');
                                string month = ((byte[])receivedBytes)[5].ToString("X").PadLeft(2, '0');
                                string day = ((byte[])receivedBytes)[6].ToString("X").PadLeft(2, '0');

                                sFullChargeDate = Convert.ToString(Convert.ToInt32(year, 16)) + "/" + Convert.ToString(Convert.ToInt32(month, 16)) + "/" + Convert.ToString(Convert.ToInt32(day, 16));

                                if (Convert.ToInt32(year, 16) > 0 && Convert.ToInt32(month, 16) > 0 && Convert.ToInt32(day, 16) > 0)
                                {
                                    strFullyChargedDate[5] = sFullChargeDate;
                                }
                                else
                                {
                                    strFullyChargedDate[5] = "N/A";
                                    lblSinceFullCharge6.Text = "?";
                                }
                            }
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "249"))
                        {
                            _ObjBLEDevices[5].BatteryType = Convert.ToInt32(((byte[])receivedBytes)[3].ToString(), 16);
                        }
                        else if (((byte[])receivedBytes)[0].ToString() == "204" && (((byte[])receivedBytes)[1].ToString() == "232"))
                        {
                            if (((byte[])receivedBytes)[0].ToString() == "204" && ((byte[])receivedBytes)[receivedBytes.Length - 1].ToString() == "207")
                            {
                                string hex = BitConverter.ToString(receivedBytes);
                                string[] subs = hex.Split('-');

                                if (subs.Length > 25)
                                {
                                    int CurrentBattType = Convert.ToInt32(subs[25]);
                                    _ObjBLEDevices[5].BatteryType = CurrentBattType;
                                }

                                if (_ObjBLEDevices[5].BatteryType == 2)
                                {
                                    if (subs.Length > 14)
                                    {
                                        bool IsHighSOCMonitorOn = false;
                                        if (subs[14] == "01" || subs[14] == "1")
                                        {
                                            IsHighSOCMonitorOn = true;
