                                _ListMultiDeviceArr04ResBytes[5].Add(receivedBytes);

                                finalData = new byte[_ListMultiDeviceArr04ResBytes[5].Count()];
                                finalData = _ListMultiDeviceArr04ResBytes[5][0].Concat(_ListMultiDeviceArr04ResBytes[5][1]).ToArray();
                            }
                        }
                        else if ((iFirstByte == 221 && iLastByte == 119) && (ReceiveCommandByUSb || _IsSFKH2Device[5]))
                        {
                            if (iSecoundByte == 3 && _ListMultiDeviceArrResBytes != null && _ListMultiDeviceArrResBytes[5].Count() > 0)
                            {
                                finalData = new byte[_ListMultiDeviceArrResBytes[5].Count()];
                                finalData = _ListMultiDeviceArrResBytes[5][0];
                            }
                            else if (iSecoundByte == 4 && _ListMultiDeviceArr04ResBytes != null && _ListMultiDeviceArr04ResBytes[5].Count() > 0)
                            {
                                finalData = new byte[_ListMultiDeviceArr04ResBytes[5].Count()];
                                finalData = _ListMultiDeviceArr04ResBytes[5][0];
                            }
                        }

                        int iFirstByteInner = Convert.ToInt32(((byte[])finalData)[1]);
                        if (iFirstByteInner == 3)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {
                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                decimal dVoltage = System.Decimal.Zero;
                                decimal dfinalAmp = System.Decimal.Zero;
                                decimal dFinalWatts = System.Decimal.Zero;
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        _ListMultiDeviceArrResBytes[5].Clear();

                                        _ObjBLEDevices[5].DeviceMacAddress = _ConnectedDevices[5].MacAddress;

                                        //Remaining AH
                                        if (subs.Length > 11)
                                        {
                                            string remaininghex = subs[8] + subs[9];
                                            int int_remainingvalue = Convert.ToInt32(remaininghex, 16);

                                            string fullhex = subs[10] + subs[11];
                                            int int_fullvalue = Convert.ToInt32(fullhex, 16);

                                            if (int_remainingvalue > 0)
                                            {
                                                _ObjBLEDevices[5].RemainingAH = Convert.ToString(Math.Round((decimal)int_remainingvalue / 100, 2));
