                                        //BMS Error
                                        if (subs.Length > 21)
                                        {
                                            byte[] byteArray = new byte[2];

                                            try
                                            {
                                                string sprotectionStatus = subs[20] + subs[21];
                                                int protectionStatus1 = Convert.ToInt32(sprotectionStatus, 16);

                                                List<int> bits = new List<int>();
