                                                            imgSecoundWarningForDevice6.Source = "packovervolt.png";
                                                            lblSecoundWarningForDevice6.Text = "Pack \novervolt";
                                                        }
                                                        else
                                                        {
                                                            SecoundWarningForDevice6.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 3)
