                                                        {
                                                            SecoundWarningForDevice6.IsVisible = true;
                                                            imgSecoundWarningForDevice6.Source = "packundervolt.png";
                                                            lblSecoundWarningForDevice6.Text = "Pack \nundervolt";
                                                        }
