                                                        {
                                                            ThirdWarningForDevice6.IsVisible = true;
                                                            imgThirdWarningForDevice6.Source = "chargeovertemp.png";
                                                            lblThirdWarningForDevice6.Text = "Charge \novertemp";
                                                            if (!UsedNewFirmwareDevices[5])
