                                                            ThirdWarningForDevice6.IsVisible = false;
                                                            if (!UsedNewFirmwareDevices[5])
                                                            {
                                                                NinethWarningForDevice6.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 5)
