                                                if (!SecoundWarningForDevice6.IsVisible && !ThirdWarningForDevice6.IsVisible && !FourthWarningForDevice6.IsVisible && !FifthWarningForDevice6.IsVisible && !SixthWarningForDevice6.IsVisible && !SeventhWarningForDevice6.IsVisible && !EightWarningForDevice6.IsVisible)
