                                                SecoundWarningForDevice6.IsVisible = ThirdWarningForDevice6.IsVisible = FourthWarningForDevice6.IsVisible = FifthWarningForDevice6.IsVisible = SixthWarningForDevice6.IsVisible = SeventhWarningForDevice6.IsVisible = EightWarningForDevice6.IsVisible = false;

                                                FirstWarningForDevice6.IsVisible = true;

                                                imgFirstWarningForDevice6.Source = "normalcell.png";
                                                lblFirstWarningForDevice6.Text = "Normal";
