                                            yy = yy + 2000;

                                            int mm = ((a >> 5) & 15);

                                            int dd = (a & 31);
                                            lblProductionDate7.Text = Convert.ToString(yy) + "-" + Convert.ToString(mm) + "-" + Convert.ToString(dd);
                                        }

                                        //BMS Temp
                                        if (subs.Length > 28)
