                            {
                                _ListMultiDeviceArr04ResBytes[7].Add(receivedBytes);

                                finalData = new byte[_ListMultiDeviceArr04ResBytes[7].Count()];
                                finalData = _ListMultiDeviceArr04ResBytes[7][0].Concat(_ListMultiDeviceArr04ResBytes[7][1]).ToArray();
                            }
                        }
                        else if ((iFirstByte == 221 && iLastByte == 119) && (ReceiveCommandByUSb || _IsSFKH2Device[7]))
                        {
                            if (iSecoundByte == 3 && _ListMultiDeviceArrResBytes != null && _ListMultiDeviceArrResBytes[7].Count() > 0)
                            {
                                finalData = new byte[_ListMultiDeviceArrResBytes[7].Count()];
                                finalData = _ListMultiDeviceArrResBytes[7][0];
                            }
                            else if (iSecoundByte == 4 && _ListMultiDeviceArr04ResBytes != null && _ListMultiDeviceArr04ResBytes[7].Count() > 0)
                            {
                                finalData = new byte[_ListMultiDeviceArr04ResBytes[7].Count()];
                                finalData = _ListMultiDeviceArr04ResBytes[7][0];
                            }
                        }

                        int iFirstByteInner = Convert.ToInt32(((byte[])finalData)[1]);
                        if (iFirstByteInner == 3)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {
                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                decimal dVoltage = System.Decimal.Zero;
                                decimal dfinalAmp = System.Decimal.Zero;
                                decimal dFinalWatts = System.Decimal.Zero;
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        _ListMultiDeviceArrResBytes[7].Clear();

                                        _ObjBLEDevices[7].DeviceMacAddress = _ConnectedDevices[7].MacAddress;

                                        //Remaining AH
                                        if (subs.Length > 11)
                                        {
                                            string remaininghex = subs[8] + subs[9];
                                            int int_remainingvalue = Convert.ToInt32(remaininghex, 16);

                                            string fullhex = subs[10] + subs[11];
                                            int int_fullvalue = Convert.ToInt32(fullhex, 16);

                                            if (int_remainingvalue > 0)
                                            {
                                                _ObjBLEDevices[7].RemainingAH = Convert.ToString(Math.Round((decimal)int_remainingvalue / 100, 2));
                                            }
                                            else
                                            {
                                                _ObjBLEDevices[7].RemainingAH = Convert.ToString(Math.Round(0.0, 2));
                                            }
                                        }

                                        //Volts
                                        if (subs.Length > 5)
                                        {
                                            string packVhex = subs[4] + subs[5];
                                            int int_packvvalue = Convert.ToInt32(packVhex, 16);
                                            dVoltage = ((decimal)int_packvvalue / 100);
                                            _ObjBLEDevices[7].Voltes = ((decimal)int_packvvalue / 100);
                                        }

                                        //Amps
                                        if (subs.Length > 7)
                                        {
                                            string currentAVhex = subs[6] + subs[7];
                                            int int_currentAvalue = Convert.ToInt32(currentAVhex, 16);

                                            int temp_amp1 = finalData[6];
                                            if ((temp_amp1 & 0x80) == 0)
                                            {

                                            }
                                            else
                                            {
                                                temp_amp1 = (byte)(~(temp_amp1 - 0x01)) * -1;
                                            }
                                            temp_amp1 = temp_amp1 * 16 * 16;
                                            int temp_amp2 = finalData[7];
                                            dfinalAmp = (decimal)(temp_amp1 + temp_amp2) / 100;

                                            _ObjBLEDevices[7].Amps = Math.Round(dfinalAmp, 2);

                                            dFinalWatts = (dfinalAmp * dVoltage);
                                            _ObjBLEDevices[7].Watts = Math.Round(dFinalWatts, 2);
                                        }

                                        if (subs.Length > 15)
                                        {
                                            string productiondate = subs[14] + subs[15];
                                            int nproductiondate = Convert.ToInt32(productiondate, 16);

                                            int a = nproductiondate;

                                            int yy = a >> 9;
                                            yy = yy + 2000;

                                            int mm = ((a >> 5) & 15);

                                            int dd = (a & 31);
                                            lblProductionDate8.Text = Convert.ToString(yy) + "-" + Convert.ToString(mm) + "-" + Convert.ToString(dd);
                                        }

                                        //BMS Temp
                                        if (subs.Length > 28)
                                        {
                                            string temp1Vhex = subs[27] + subs[28];
                                            int int_temp1Avalue = Convert.ToInt32(temp1Vhex, 16);
                                            decimal dec_temp1 = ((decimal)int_temp1Avalue / 10) - 273.15M;
                                            if (IsFahrenheit)
                                            {
                                                dec_temp1 = (dec_temp1 * 9) / 5 + 32;
                                            }
                                            _ObjBLEDevices[7].BMSTempreture = Convert.ToDecimal(dec_temp1);
                                        }

                                        //Case Temp
                                        if (subs.Length > 30)
                                        {
                                            string temp2Vhex = subs[29] + subs[30];
                                            int int_temp2Avalue = Convert.ToInt32(temp2Vhex, 16);
                                            decimal dec_temp2 = ((decimal)int_temp2Avalue / 10) - 273.15M;
                                            if (IsFahrenheit)
                                            {
                                                dec_temp2 = (dec_temp2 * 9) / 5 + 32;
                                            }
                                            _ObjBLEDevices[7].CaseTempreture = Convert.ToDecimal(dec_temp2);
                                        }

                                        //Case Temp 2
                                        if (subs.Length > 32)
                                        {
                                            string temp3Vhex = subs[31] + subs[32];
                                            int int_temp3Avalue = Convert.ToInt32(temp3Vhex, 16);
                                            decimal dec_temp3 = ((decimal)int_temp3Avalue / 10) - 273.15M;

                                            if (IsFahrenheit)
                                            {
                                                dec_temp3 = (dec_temp3 * 9) / 5 + 32; //covert to fahranite
                                            }
                                            _ObjBLEDevices[7].CaseTempreture2 = Convert.ToDecimal(dec_temp3);
                                        }

                                        // Charging / Dischargin 
                                        if (subs.Length > 24)
                                        {
                                            //Soc Heating Status
                                            string hexvalue = subs[24];
                                            int decimalValue = Convert.ToInt32(hexvalue, 16);
                                            string binaryString = Convert.ToString(decimalValue, 2).PadLeft(5, '0');
                                            string[] bytes = new string[binaryString.Length];

                                            for (int i = 0; i < binaryString.Length; i++)
                                            {
                                                bytes[i] = Convert.ToString(binaryString[i]);
                                            }
                                            if (bytes != null && bytes.Length > 0)
                                            {
                                                if (bytes[0] == "1")
                                                {
                                                    TenthWarningForDevice8.IsVisible = true;

                                                    imgTenthWarningForDevice8.Source = "soclimit.png";
                                                    lblTenthWarningForDevice8.Text = "SOC Limit";
                                                }
                                                else
                                                {
                                                    TenthWarningForDevice8.IsVisible = false;
                                                }

                                                if (bytes[1] == "1")
                                                {
                                                    NinethWarningForDevice8.IsVisible = true;

                                                    imgNinethWarningForDevice8.Source = "heatingpadson.png";
                                                    lblNinethWarningForDevice8.Text = "Heating on";
                                                }
                                                else
                                                {
                                                    NinethWarningForDevice8.IsVisible = false;
                                                }

                                                // Charging / Discharging

                                                // Discharging 
                                                if (bytes[3] == "1")
                                                {
                                                    //discharge chalu                                                        
                                                    _ObjBLEDevices[7].IsDischargingOn = true;
                                                }
                                                else
                                                {
                                                    //discharge bandh                                                        
                                                    _ObjBLEDevices[7].IsDischargingOn = false;
                                                }

                                                // Charging
                                                if (bytes[4] == "1")
                                                {
                                                    //charging chalu                                                                                                                    
                                                    _ObjBLEDevices[7].IsChargingOn = true;
                                                }
                                                else
                                                {
                                                    //charging bandh                                                                                                                    
                                                    _ObjBLEDevices[7].IsChargingOn = false;
                                                }
                                            }
                                        }

                                        //BMS Error
                                        if (subs.Length > 21)
                                        {
                                            byte[] byteArray = new byte[2];

                                            try
                                            {
                                                string sprotectionStatus = subs[20] + subs[21];
                                                int protectionStatus1 = Convert.ToInt32(sprotectionStatus, 16);

                                                List<int> bits = new List<int>();
                                                for (int i = 0; i <= 15; i++)
                                                {
                                                    bits.Add(((int)((protectionStatus1 >> i) & 0x01)));
                                                }

                                                for (int i = 0; i < 15; i++)
                                                {
                                                    if (i == 0)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FirstWarningForDevice8.IsVisible = true;
                                                            imgFirstWarningForDevice8.Source = "cellovervolt.png";
                                                            lblFirstWarningForDevice8.Text = "Cell \novervolt";
                                                        }
                                                        else
                                                        {
                                                            FirstWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 1)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FirstWarningForDevice8.IsVisible = true;
                                                            imgFirstWarningForDevice8.Source = "cellundervolt.png";
                                                            lblFirstWarningForDevice8.Text = "Cell \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!FirstWarningForDevice8.IsVisible)
                                                            {
                                                                FirstWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 2)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice8.IsVisible = true;
                                                            imgSecoundWarningForDevice8.Source = "packovervolt.png";
                                                            lblSecoundWarningForDevice8.Text = "Pack \novervolt";
                                                        }
                                                        else
                                                        {
                                                            SecoundWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 3)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SecoundWarningForDevice8.IsVisible = true;
                                                            imgSecoundWarningForDevice8.Source = "packundervolt.png";
                                                            lblSecoundWarningForDevice8.Text = "Pack \nundervolt";
                                                        }
                                                        else
                                                        {
                                                            if (!SecoundWarningForDevice8.IsVisible)
                                                            {
                                                                SecoundWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 4)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            ThirdWarningForDevice8.IsVisible = true;
                                                            imgThirdWarningForDevice8.Source = "chargeovertemp.png";
                                                            lblThirdWarningForDevice8.Text = "Charge \novertemp";
                                                            if (!UsedNewFirmwareDevices[7])
                                                            {
                                                                if (_ObjDeviceInformations[7].HeatingPadWarning)
                                                                {
                                                                    NinethWarningForDevice8.IsVisible = true;

                                                                    imgNinethWarningForDevice8.Source = "heatingpadson.png";
                                                                    lblNinethWarningForDevice8.Text = "Heating on";
                                                                }
                                                            }
                                                        }
                                                        else
                                                        {
                                                            ThirdWarningForDevice8.IsVisible = false;
                                                            if (!UsedNewFirmwareDevices[7])
                                                            {
                                                                NinethWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 5)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            ThirdWarningForDevice8.IsVisible = true;
                                                            imgThirdWarningForDevice8.Source = "chargeundertemp.png";
                                                            lblThirdWarningForDevice8.Text = "Charge \nundertemp";
                                                        }
                                                        else
                                                        {
                                                            if (!ThirdWarningForDevice8.IsVisible)
                                                            {
                                                                ThirdWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 6)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FourthWarningForDevice8.IsVisible = true;
                                                            imgFourthWarningForDevice8.Source = "dischargeovertemp.png";
                                                            lblFourthWarningForDevice8.Text = "Discharge \novertemp";
                                                        }
                                                        else
                                                        {
                                                            FourthWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 7)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FourthWarningForDevice8.IsVisible = true;
                                                            imgFourthWarningForDevice8.Source = "dischargeundertemp.png";
                                                            lblFourthWarningForDevice8.Text = "Discharge \nundertemp";
                                                        }
                                                        else
                                                        {
                                                            if (!FourthWarningForDevice8.IsVisible)
                                                            {
                                                                FourthWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 8)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FifthWarningForDevice8.IsVisible = true;
                                                            imgFifthWarningForDevice8.Source = "chargeovercurrent.png";
                                                            lblFifthWarningForDevice8.Text = "Charge \novercurrent";
                                                        }
                                                        else
                                                        {
                                                            FifthWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 9)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            FifthWarningForDevice8.IsVisible = true;
                                                            imgFifthWarningForDevice8.Source = "dischargeovercurrent.png";
                                                            lblFifthWarningForDevice8.Text = "Discharge \novercurrent";
                                                        }
                                                        else
                                                        {
                                                            if (!FifthWarningForDevice8.IsVisible)
                                                            {
                                                                FifthWarningForDevice8.IsVisible = false;
                                                            }
                                                        }
                                                    }
                                                    else if (i == 10)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SixthWarningForDevice8.IsVisible = true;
                                                            imgSixthWarningForDevice8.Source = "shortcircuit.png";
                                                            lblSixthWarningForDevice8.Text = "Short \nCircuit";
                                                        }
                                                        else
                                                        {
                                                            SixthWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 11)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            SeventhWarningForDevice8.IsVisible = true;
                                                            imgSeventhWarningForDevice8.Source = "frontendicerror.png";
                                                            lblSeventhWarningForDevice8.Text = "Frontend \nIC error";
                                                        }
                                                        else
                                                        {
                                                            SeventhWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                    else if (i == 12)
                                                    {
                                                        if (bits[i] == 1)
                                                        {
                                                            EightWarningForDevice8.IsVisible = true;
                                                            imgEightWarningForDevice8.Source = "locking.png";
                                                            lblEightWarningForDevice8.Text = "Locking";
                                                        }
                                                        else
                                                        {
                                                            EightWarningForDevice8.IsVisible = false;
                                                        }
                                                    }
                                                }

                                                if (!SecoundWarningForDevice8.IsVisible && !ThirdWarningForDevice8.IsVisible && !FourthWarningForDevice8.IsVisible && !FifthWarningForDevice8.IsVisible && !SixthWarningForDevice8.IsVisible && !SeventhWarningForDevice8.IsVisible && !EightWarningForDevice8.IsVisible)
                                                {
                                                    FirstWarningForDevice8.IsVisible = true;

                                                    imgFirstWarningForDevice8.Source = "normalcell.png";
                                                    lblFirstWarningForDevice8.Text = "Normal";
                                                }
                                            }
                                            catch
                                            {
                                                SecoundWarningForDevice8.IsVisible = ThirdWarningForDevice8.IsVisible = FourthWarningForDevice8.IsVisible = FifthWarningForDevice8.IsVisible = SixthWarningForDevice8.IsVisible = SeventhWarningForDevice8.IsVisible = EightWarningForDevice8.IsVisible = false;

                                                FirstWarningForDevice8.IsVisible = true;

                                                imgFirstWarningForDevice8.Source = "normalcell.png";
                                                lblFirstWarningForDevice8.Text = "Normal";
                                            }
                                        }

                                        //FirmwareVeriosn
                                        if (subs.Length > 22)
                                        {
                                            double veriosn = Convert.ToDouble(subs[22]);
                                            _ObjBLEDevices[7].FirmwareVeriosn = Math.Round(veriosn / 10, 1);
                                            if (_ObjBLEDevices[7].FirmwareVeriosn >= 6.4)
                                            {
                                                UsedNewFirmwareDevices[7] = true;
                                            }
                                        }

                                        int batterystatuspercent = 0;

                                        //SOC
                                        if (subs.Length > 23)
                                        {
                                            batterystatuspercent = Convert.ToInt32(subs[23], 16);
                                            _ObjBLEDevices[7].SOC = batterystatuspercent + "% SOC";
                                        }
                                    }
                                    else
                                    {
                                        _ListMultiDeviceArrResBytes[7].Clear();
                                        await CheckSumFailer(7);
                                    }
                                }

                            }
                        }
                        else if (iFirstByteInner == 4)
                        {
                            if (finalData[finalData.Length - 1].ToString() == "119")
                            {

                                string hex = BitConverter.ToString(finalData);
                                string[] subs = hex.Split('-');
                                //declaring a variable and assigning hex value
                                if (subs != null && subs.Length > 0 && finalData[0].ToString() == "221")
                                {
                                    int SumOfByte = 0;
                                    for (int i = 2; i < (subs.Count() - 3); i++)
                                    {
                                        SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                                    }
                                    string CheckSum = (65536 - SumOfByte).ToString("X");
                                    if (CheckSum == Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]))
                                    {
                                        if (subs.Length > 4)
                                        {
                                            try
                                            {
                                                List<TempCellInfo> _Bdata8 = _ObjBatteryData.BData8.Select(item => new TempCellInfo { cellvolts = item.CellVolts }).ToList();

                                                if (!bSameCell[7])
                                                {
                                                    _ObjBatteryData.BData8 = new ObservableCollection<CellInfo>();
                                                    await RebindModel(7);
                                                }
                                                string cellCount = subs[2] + subs[3];
                                                int ncellCount = Convert.ToInt32(cellCount, 16);
                                                ncellCount = ncellCount / 2;
                                                if (ncellCount > 0)
                                                {
                                                    //SeriesColors.Clear();
                                                    for (int i = 0; i < ncellCount; i++)
                                                    {
                                                        int ntemp = (i * 2) + 4;

                                                        string hex_value = subs[ntemp] + subs[ntemp + 1];

                                                        //converting hex to integer
                                                        int int_value = Convert.ToInt32(hex_value, 16);

                                                        decimal dcellvolts = ((decimal)int_value / 1000.00M);
                                                        if (dcellvolts >= (decimal)1.5 && dcellvolts <= (decimal)4.5)
                                                        {
                                                            _ObjBatteryData.BData8[i].CellVolts = Math.Round(dcellvolts, 2);

                                                            if (dcellvolts >= 0 && dcellvolts <= 2.749M)
                                                            {
                                                                _ObjBatteryData.Battery8Colors[i] = Colors.Red;
                                                            }
                                                            else if (dcellvolts >= 2.750M && dcellvolts <= 2.999M)
                                                            {
                                                                _ObjBatteryData.Battery8Colors[i] = Colors.Orange;
                                                                _ObjBatteryData.Battery8TextColors[i] = Colors.Black;
                                                            }
                                                            else if (dcellvolts >= 3M && dcellvolts <= 3.099M)
                                                            {
                                                                _ObjBatteryData.Battery8Colors[i] = Colors.Yellow;
                                                                _ObjBatteryData.Battery8TextColors[i] = Colors.Black;
                                                            }
                                                            else if (dcellvolts >= 3.1M && dcellvolts <= 4M)
                                                            {
                                                                _ObjBatteryData.Battery8Colors[i] = Colors.Green;
                                                            }
                                                            else
                                                            {
                                                                _ObjBatteryData.Battery8Colors[i] = Colors.Green;
                                                            }
                                                        }
                                                    }

                                                    chartItemSourceEighthBattery.ItemsSource = _ObjBatteryData.BData8;
                                                    chartItemSourceEighthBattery.PaletteBrushes = _ObjBatteryData.Battery8Colors;

                                                    for (int i = 0; i < _ObjBatteryData.BData8.Count(); i++)
                                                    {
                                                        if (_ObjBatteryData.BData8[i].CellVolts == _Bdata8[i].cellvolts)
                                                        {
                                                            bSameCell[7] = true;
                                                        }
                                                        else
                                                        {
                                                            bSameCell[7] = false;
                                                        }
                                                    }

                                                    if (BmsDeviceCount == 8)
                                                    {
                                                        await ShowBusyindicatior(false);
                                                    }
                                                }
                                            }
                                            catch { }
                                        }
                                    }
                                    else
                                    {
                                        _ListMultiDeviceArr04ResBytes[7].Clear();
                                        await CheckSumFailer(7);
                                    }
                                }
                            }
                        }

                    }
                    else
                    {
                        await CheckSumFailer(7);
                    }
                }
            }
            catch (Exception ex)
            {

            }
        }
        private async Task Displaydata(BLEDevice objBleDevice, int ModelIndex)
        {
            try
            {
                MainThread.BeginInvokeOnMainThread(async () =>
                {
                    BindingContext = _ObjBatteryData;

                    Color colorGauge = Colors.Black;

                    double gaugeBattryStatus = 0.0;
                    if (!string.IsNullOrWhiteSpace(objBleDevice.SOC))
                    {
                        gaugeBattryStatus = Convert.ToDouble(Convert.ToString(objBleDevice.SOC).Replace("% SOC", ""));
                    }
                    else
                    {
                        gaugeBattryStatus = 0.0;
                    }

                    if (gaugeBattryStatus >= 65 && gaugeBattryStatus <= 100)
                    {
                        colorGauge = Colors.Green;
                    }
                    else if (gaugeBattryStatus >= 30 && gaugeBattryStatus < 65)
                    {
                        colorGauge = Colors.Orange;
                    }
                    else if (gaugeBattryStatus >= 0 && gaugeBattryStatus < 30)
                    {
                        colorGauge = Colors.Red;
                    }
                    objBleDevice.Voltes = Math.Round(objBleDevice.Voltes * 1.00M, 2);
                    objBleDevice.Amps = Math.Round(objBleDevice.Amps * 1.00M, 2);
                    objBleDevice.Watts = Math.Round(objBleDevice.Watts * 1.00M, 2);
                    objBleDevice.BMSTempreture = Math.Round(objBleDevice.BMSTempreture * 1.00M, 1);
                    objBleDevice.CaseTempreture = Math.Round(objBleDevice.CaseTempreture * 1.00M, 1);
                    objBleDevice.CaseTempreture2 = Math.Round(objBleDevice.CaseTempreture2 * 1.00M, 1);

                    await UpdateViewModel(ModelIndex, objBleDevice, gaugeBattryStatus);

                    await SetBMSCaseTempretureColor(ModelIndex, objBleDevice.CaseTempreture);

                    if (ModelIndex == 0)
                    {
                        gridCircularOne.IsVisible = true;
                        gaugeTempDeviceOne.IsVisible = true;
                        lblModel1.Text = objBleDevice.BarcodeValue;
                        lblVolts1.Text = "" + objBleDevice.Voltes;
                        if (objBleDevice.Amps == 0)
                        {
                            lblAmps1.Text = "0.00";
                        }
                        else
                        {
                            lblAmps1.Text = "" + objBleDevice.Amps;
                        }
                        lblWatts1.Text = "" + objBleDevice.Watts;

                        SetTemperatureLabels(ModelIndex, objBleDevice, lblBMSTemp1, lblCaseTemp1, lblCaseTemp1Mbl, lblGaugeTempDeviceOne, lblCaseTemp21, lblCaseTemp21Mbl);

                        lblRemaining1.Text = "" + objBleDevice.RemainingAH;
                        gaugeSocForDevice1.Text = Math.Round(gaugeBattryStatus) + "%";
                        gaugeSocForDevice1.TextColor = colorGauge;

                        if (objBleDevice.IsChargingOn)
                        {
                            imgChargingEnableDisableForDevice1.Source = "chargingenabled.png";
                        }
                        else
                        {
                            imgChargingEnableDisableForDevice1.Source = "chargingdisabled.png";
                        }

                        if (objBleDevice.IsDischargingOn)
                        {
                            imgDischargingEnableDisableForDevice1.Source = "dischargingenabled.png";
                        }
                        else
                        {
                            imgDischargingEnableDisableForDevice1.Source = "dischargingdisabled.png";
                        }

                        if (!string.IsNullOrWhiteSpace(objBleDevice.DeviceMacAddress))
                        {
                            string NickName = Preferences.Get(objBleDevice.DeviceMacAddress, string.Empty);
                            if (!string.IsNullOrWhiteSpace(NickName))
                            {
                                lblDeviceNameForDevice1.Text = NickName;
                            }
                            else
                            {
