                        }

                        // Hitting Pads
                        var BMSDevices = new[] { NinethWarningForDevice1, NinethWarningForDevice2, NinethWarningForDevice3, NinethWarningForDevice4, NinethWarningForDevice5, NinethWarningForDevice6, NinethWarningForDevice7, NinethWarningForDevice8 };

                        bool AnyBmsHasHitingOn = BMSDevices.Any(x => x.IsVisible);
                        bool AllBMSHasHitingOff = BMSDevices.All(x => x.IsVisible);

                        string HeatingPadImage = AnyBmsHasHitingOn && !AllBMSHasHitingOff ? "heatingpadred.png" : "heatingpadgray.png";
                        imgAutoHeatingPadIcon.Source = ImageSource.FromFile(HeatingPadImage);

                        if (HeatingPadImage == "heatingpadred.png")
                        {
                            if (!_isHeatingPadIconFlashing)
                            {
                                _isHeatingPadIconFlashing = true;

                                _ = Task.Run(async () =>
                                {
                                    while (_isHeatingPadIconFlashing)
                                    {
                                        bool AnyBmsHasHitingOn = BMSDevices.Any(x => x.IsVisible);
                                        bool AllBMSHasHitingOff = BMSDevices.All(x => x.IsVisible);

                                        if (!AnyBmsHasHitingOn || AllBMSHasHitingOff)
                                        {
                                            _isHeatingPadIconFlashing = false;
                                            break;
                                        }

                                        await MainThread.InvokeOnMainThreadAsync(() => imgAutoHeatingPadIcon.IsVisible = false);
                                        await Task.Delay(700);

                                        await MainThread.InvokeOnMainThreadAsync(() => imgAutoHeatingPadIcon.IsVisible = true);
                                        await Task.Delay(700);
                                    }
                                });
                            }
                        }
                        else
                        {
                            _isHeatingPadIconFlashing = false;
                            imgAutoHeatingPadIcon.IsVisible = true;
                        }

                        #endregion Auto Dashboard Details Bindings

                        _ObjBatteryData.SingleGraphBattery = new ObservableCollection<CellInfoForCombine>();
                        _ObjBatteryData.SingleGraphCellColor = new ObservableCollection<Brush>();

                        for (int i = 0; i < BmsDeviceCount; i++)
                        {
                            await RebindModel(i, false, true);
                        }

                        if (objMultiDeviceViewModel.arrFirmwareVersion != null && objMultiDeviceViewModel.arrFirmwareVersion.Length > 0 && FirmwareCheckCount != 3)
                        {
                            if (objMultiDeviceViewModel.arrFirmwareVersion.Length > 0)
                            {
                                stackHeatingBalancing.IsVisible = EnableHeatingAndSeriesBalance = objMultiDeviceViewModel.arrFirmwareVersion.All(item => item >= 6.4);
                            }

                            FirmwareCheckCount++;
                        }

                        if (!isHeatingBalanceUpdating && MultiSKFTabView.SelectedIndex != 2)
                        {
                            await ShowBusyindicatior(false);
                            IsPageFirstTimeLoading = false;
                        }
                    }
                });
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        public async Task BindFuelIndicator(int ModelIndex)
        {
            // Initialize list (same style, but using loop)
            ListFuelIndicator.Clear();

            int Width = Device.Idiom == TargetIdiom.Tablet ? 18 : 15;

            int[] HeightsTablet = { 110, 100, 90, 80, 70, 60, 50, 40, 30 };
            int[] HeightsMobile = { 90, 80, 70, 60, 50, 40, 30, 25, 20 };

            int[] Heights = Device.Idiom == TargetIdiom.Tablet ? HeightsTablet : HeightsMobile;

            for (int i = 0; i < 9; i++)
            {
                Color color = Color.FromHex("#99C817");

                if (i >= 4 && i <= 6)
                {
                    color = Color.FromHex("#FDEB48");
                }
                else if (i == 7)
                {
                    color = Color.FromHex("#F26D24");
                }
                else if (i == 8)
                {
                    color = Color.FromHex("#D72626");
                }

                ListFuelIndicator.Add(new FuelIndicator { ID = i + 1, ShowArrow = false, IndicatorColor = color, IndicatorWidth = Width, IndicatorHeight = Heights[i] });
            }

            // Fuel SOC 
            double SOC = 0.0;

            if (SettingValue == "Parallel")
            {
                SOC = Math.Round(objMultiDeviceViewModel.TotalSOC / ModelIndex, 2);
            }
            else
            {
                SOC = Math.Round(objMultiDeviceViewModel.arrTotalSOC.Min(), 2);
            }

            if (SOC >= 0)
            {
                // SAME exact range logic
                if (SOC >= 0 && SOC <= 10.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 9) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 11 && SOC <= 30.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 8) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 31 && SOC <= 40.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 7) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 41 && SOC <= 50.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 6) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 51 && SOC <= 60.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 5) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 61 && SOC <= 70.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 4) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 71 && SOC <= 80.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 3) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 81 && SOC <= 90.99)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 2) { item.ShowArrow = true; }
                    }
                }
                else if (SOC >= 91)
                {
                    foreach (var item in ListFuelIndicator)
                    {
                        if (item.ID == 1) { item.ShowArrow = true; }
                    }
                }

                // SAME greying logic (but no LINQ)
                for (int i = 0; i < ListFuelIndicator.Count; i++)
                {
                    if (ListFuelIndicator[i].ShowArrow == true)
                    {
                        for (int j = 0; j < ListFuelIndicator.Count; j++)
                        {
                            if (ListFuelIndicator[j].ID < ListFuelIndicator[i].ID)
                            {
                                ListFuelIndicator[j].IndicatorColor = Color.FromHex("#DFDFDE");
                            }
                        }
                    }
                }

                lstFuelIndicator.ItemsSource = ListFuelIndicator.OrderByDescending(m => m.ID).ToArray();
            }
        }
