        private async Task ReadBMSCodeWith0ACommand(int ModelIndex)
        {
            try
            {
                int tCount = 0;

                while (tCount < 2) // Register 0A
                {
                    await SendWriteOrReadStartCommandToBMS(ModelIndex);

                    await Task.Delay(100);

                    // var getRegister0AValue = new byte[] { 0xdd, 0xa5, 0x0a, 0x00, 0xff, 0xf6, 0x77 };
                    var getRegister0AValue = _ObjProtocols[ModelIndex].CreateReadCommand(RegisterEnum.REG_FRESET);
                    await SendCommandToBMS(getRegister0AValue, ModelIndex);

                    await Task.Delay(100);

                    await SendWriteOrReadEndCommandToBMS(ModelIndex);

                    await Task.Delay(500);

                    if ((ModelIndex == 1 && !UsedNewFirmwareDevices[0]) || (ModelIndex == 2 && !UsedNewFirmwareDevices[1]) || (ModelIndex == 3 && !UsedNewFirmwareDevices[2]) || (ModelIndex == 4 && !UsedNewFirmwareDevices[3]))
                    {
                        tCount++;
                    }
                    else
                    {
                        break;
                    }
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
