        private SemaphoreSlim[] _bleWriteLocks = Enumerable.Range(0, 8).Select(_ => new SemaphoreSlim(1, 1)).ToArray();
        public async Task SendCommandToBMS(byte[] SendCommand, int ModelIndex)
        {
            await _bleWriteLocks[ModelIndex].WaitAsync();
            try
            {
                string data = Serializer.Serialize(SendCommand);
                data += "^" + ModelIndex;
                await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.byteCommand, data);
            }
            catch (Exception ex)
            {
            }
            finally
            {
                _bleWriteLocks[ModelIndex].Release();
            }
        }
