        private Task<bool> VerifyByteUsingChecksum(byte[] bytes)
        {
            bool bProceed = false;
            try
            {
                byte byte0 = bytes[0];
                byte byte1 = bytes[1];

                if (byte0 == 221 && bytes.Length < 7)
                {
                    return Task.FromResult(false);
                }

                byte byteLast1 = bytes[bytes.Length - 1];
                byte byteLast2 = bytes[bytes.Length - 2];
                byte byteLast3 = bytes[bytes.Length - 3];

                if (byte0 != 221 || byte1 == 3 || byte1 == 4 || byte1 == 7)
                    return Task.FromResult(true);

                if (byte0 == 221 && byteLast3 == 0 && byteLast2 == 0 && byteLast1 == 119)
                    return Task.FromResult(true);

                string hex = BitConverter.ToString(bytes);
                string[] subs = hex.Split('-');
                int SumOfByte = 0;
                for (int i = 2; i < (subs.Count() - 3); i++)
                {
                    SumOfByte = SumOfByte + Convert.ToInt32(subs[i], 16);
                }
                string CheckSum = (65536 - SumOfByte).ToString("X");
                string Actualcecksum = Convert.ToString(subs[subs.Count() - 3] + subs[subs.Count() - 2]);

                return Task.FromResult(CheckSum == Actualcecksum);
            }
            catch (Exception ex)
            {
                // TODO: Log ex
                return Task.FromResult(false);
            }
        }
