        private async Task LandscapDesignForTab(double width, double height)
        {
            try
            {
                #region Main Tab

                gridCircularOne.WidthRequest = gridCircularTwo.WidthRequest = gridCircularThree.WidthRequest = gridCircularFour.WidthRequest = (width / 2) - 15;
                gridCircularFive.WidthRequest = gridCircularSix.WidthRequest = gridCircularSeven.WidthRequest = gridCircularEight.WidthRequest = (width / 2) - 15;

                gaugeOne.WidthRequest = stackMainGaugeOne.MinimumWidthRequest = stackMainGaugeOne.WidthRequest = ((gridCircularOne.WidthRequest / 100) * 40);
                gaugeTwo.WidthRequest = stackMainGaugeTwo.MinimumWidthRequest = stackMainGaugeTwo.WidthRequest = ((gridCircularOne.WidthRequest / 100) * 40);
                gaugeThree.WidthRequest = stackMainGaugeThree.MinimumWidthRequest = stackMainGaugeThree.WidthRequest = ((gridCircularOne.WidthRequest / 100) * 40);
                gaugeFour.WidthRequest = stackMainGaugeFour.MinimumWidthRequest = stackMainGaugeFour.WidthRequest = ((gridCircularOne.WidthRequest / 100) * 40);

                gaugeFive.WidthRequest = stackMainGaugeFive.MinimumWidthRequest = stackMainGaugeFive.WidthRequest = ((gridCircularFive.WidthRequest / 100) * 40);
                gaugeSix.WidthRequest = stackMainGaugeSix.MinimumWidthRequest = stackMainGaugeSix.WidthRequest = ((gridCircularFive.WidthRequest / 100) * 40);
                gaugeSeven.WidthRequest = stackMainGaugeSeven.MinimumWidthRequest = stackMainGaugeSeven.WidthRequest = ((gridCircularFive.WidthRequest / 100) * 40);
                gaugeEight.WidthRequest = stackMainGaugeEight.MinimumWidthRequest = stackMainGaugeEight.WidthRequest = ((gridCircularFive.WidthRequest / 100) * 40);

                stackMainBordersOne.Orientation = stackMainBordersTwo.Orientation = StackOrientation.Horizontal;
                stackMainBordersThree.Orientation = stackMainBordersFour.Orientation = StackOrientation.Horizontal;

                stackMainBoxOne.WidthRequest = width - stackMainGaugeOne.WidthRequest;
                stackMainBoxTwo.WidthRequest = width - stackMainGaugeTwo.WidthRequest;
                stackMainBoxThree.WidthRequest = width - stackMainGaugeThree.WidthRequest;
                stackMainBoxFour.WidthRequest = width - stackMainGaugeFour.WidthRequest;

                stackMainBoxFive.WidthRequest = width - stackMainGaugeFive.WidthRequest;
                stackMainBoxSix.WidthRequest = width - stackMainGaugeSix.WidthRequest;
                stackMainBoxSeven.WidthRequest = width - stackMainGaugeSeven.WidthRequest;
                stackMainBoxEight.WidthRequest = width - stackMainGaugeEight.WidthRequest;

                if (BmsDeviceCount == 3)
                {
                    gridCircularThree.HorizontalOptions = LayoutOptions.StartAndExpand;
