        private async void btnTemperatureUnitUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                isHeatingBalanceUpdating = true;
                await ShowBusyindicatior(true);

                if (rdCelsius.IsChecked == true)
                {
                    Preferences.Set("CelsiusorFahrenheitMulti", "Celsius");
                }
                else if (rdFahrenheit.IsChecked == true)
                {
                    Preferences.Set("CelsiusorFahrenheitMulti", "Fahrenheit");
                }

                await btnTemperatureUnitRead();

                await Task.Delay(300);

                await ShowBusyindicatior(true);

                if (rdLowTempcharging.IsChecked)
                {
                    await SetLowTempHeatingMode(Convert.ToInt32(rdLowTempcharging.ClassId));
                }
                else if (rdStandbyHeating.IsChecked)
                {
                    await SetLowTempHeatingMode(Convert.ToInt32(rdStandbyHeating.ClassId));
                }
                else if (rdDisabledORLowTempProtectionOnly.IsChecked)
                {
                    await SetLowTempHeatingMode(Convert.ToInt32(rdDisabledORLowTempProtectionOnly.ClassId));
                }

                isHeatingBalanceUpdating = false;
                await ShowBusyindicatior(false);

                if (sCelsiusorFahrenheit == "Celsius" || sCelsiusorFahrenheit == "Fahrenheit")
                {
                    await ShowDisplayPopup("Success", "Setting updated");
                }
                else
                {
                    await ShowDisplayPopup("NotSuccess", "Setting not updated, Please Re-try");
                }
            }
            catch (Exception ex)
            {
                await ShowBusyindicatior(false);
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task ChargingAndDischarginOnAndOff(string Status, string StatusMode, int ModelIndex)
        {
            try
            {
                bool CharginOn = false;
                bool DischargingOn = false;
                if (Status == "ChargingOn")
                {
                    CharginOn = true;
                }
                else if (Status == "DischargingOn")
                {
                    DischargingOn = true;
                }

                if (StatusMode == "Charging")
                {
                    if (CharginOn)
                    {
                        for (int i = 0; i < 2; i++)
                        {
                            if (!_ObjBLEDevices[ModelIndex].IsChargingOn)
                            {
                                // var ChargingOn = new byte[] { 0xdd, 0x5a, 0xe1, 0x02, 0x00, 0x00, 0xff, 0x1d, 0x77 };  //charging chalu karava mate nu
                                var ChargingOn = _ObjProtocols[ModelIndex].CreateCustomWriteCommand(RegisterEnum.REG_CTRL_MOSFET, "02", 0);
                                await SendCommandToBMS(ChargingOn, ModelIndex);

                                await Task.Delay(2000);
                            }
                        }
                    }
                    else
                    {
                        for (int i = 0; i < 2; i++)
                        {
                            if (_ObjBLEDevices[ModelIndex].IsChargingOn)
                            {
                                // var ChargingOff = new byte[] { 0xdd, 0x5a, 0xe1, 0x02, 0x00, 0x01, 0xff, 0x1c, 0x77 };  // charging bandh karava mate nu
                                var ChargingOff = _ObjProtocols[ModelIndex].CreateCustomWriteCommand(RegisterEnum.REG_CTRL_MOSFET, "02", 1);
                                await SendCommandToBMS(ChargingOff, ModelIndex);

                                await Task.Delay(2000);
                            }
                        }

                    }
                }
                else
                {
                    if (DischargingOn)
                    {
                        for (int i = 0; i < 2; i++)
                        {
                            if (!_ObjBLEDevices[ModelIndex].IsDischargingOn)
                            {
                                // var vDischargingOn = new byte[] { 0xdd, 0x5a, 0xe1, 0x02, 0x00, 0x02, 0xff, 0x1b, 0x77 };  // discharging chalu karava mate nu
                                var vDischargingOn = _ObjProtocols[ModelIndex].CreateCustomWriteCommand(RegisterEnum.REG_CTRL_MOSFET, "02", 2);
                                await SendCommandToBMS(vDischargingOn, ModelIndex);

                                await Task.Delay(2000);
                            }
                        }
                    }
                    else
                    {
                        for (int i = 0; i < 2; i++)
                        {
                            if (_ObjBLEDevices[ModelIndex].IsDischargingOn)
                            {
                                // var DischargingOff = new byte[] { 0xdd, 0x5a, 0xe1, 0x02, 0x00, 0x03, 0xff, 0x1a, 0x77 };  // discharging bandh karava mate nu
                                var DischargingOff = _ObjProtocols[ModelIndex].CreateCustomWriteCommand(RegisterEnum.REG_CTRL_MOSFET, "02", 3);
                                await SendCommandToBMS(DischargingOff, ModelIndex);

                                await Task.Delay(2000);
                            }
                        }
                    }
                }
            }
            catch
            {

            }
        }
        private async void UpdateToolTabValueinVirtualBattery()
        {
            try
            {
                string BatterySetupSetting = string.Empty;
                string MacAddress = string.Empty;
                string strVirtualBatteryValue = string.Empty;
                if (BmsDeviceCount == 2)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforTwo";
                }
                else if (BmsDeviceCount == 3)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforThree";
                }
                else if (BmsDeviceCount == 4)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforFour";
                }
                else if (BmsDeviceCount == 5)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforFive";
                }
                else if (BmsDeviceCount == 6)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforSix";
                }
                else if (BmsDeviceCount == 7)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforSeven";
                }
                else if (BmsDeviceCount == 8)
                {
                    BatterySetupSetting = "BatteryConnectionSetupforEight";
                }

                strVirtualBatteryValue = Preferences.Get(BatterySetupSetting, string.Empty);

                strVirtualBatteryValue = strVirtualBatteryValue + "|" + AmpsDrawWarning + "|" + VoltsDrawWarning + "|" + BalanceTemperatureLimit + "|" + LowTempActivation + "|" + HeatingMode;

                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    MacAddress = _ConnectedDevices[i].MacAddress;
                    strVirtualBatteryValue += "|" + MacAddress;
                }

                string VirtualBatteryName = Preferences.Get("SelectedVirtualBatteryName", string.Empty);

                Preferences.Set(VirtualBatteryName, strVirtualBatteryValue);
            }
            catch (Exception ex)
            {
                await ShowBusyindicatior(false);
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async void btnClearLockingAlarm_Clicked(object sender, EventArgs e)
        {
            try
