        // Auto DashBoard
        private async void btnOverAmpTimeOut_Clicked(object sender, EventArgs e)
        {
            try
            {
                bool isValid = false;
                await ShowBusyindicatior(true);

                int NewOverAmpTimeOutValue = (int)rangesliderOverAmpTimeOut.Value;

                int tCount = 0;

                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    await ShowBusyindicatior(true, $"Updating battery \n{i + 1} of {BmsDeviceCount}...");

                    while (tCount < 2) // Register 3f
                    {
                        await SendWriteOrReadStartCommandToBMS(i);

                        await Task.Delay(150);

                        string ampTimeOut = Convert.ToInt32(rangesliderOverAmpTimeOut.Value).ToString("X") + "20";

                        var WriteToReg29 = _ObjProtocols[i].CreateCustomWriteCommand(RegisterEnum.REG_DSGOC_DELAYS, "02", Convert.ToUInt32(ampTimeOut, 16));
                        await SendCommandToBMS(WriteToReg29, i);

                        await Task.Delay(150);

                        await SendWriteOrReadEndCommandToBMS(i);

                        await Task.Delay(200);

                        await ShowBusyindicatior(true, $"Updating battery \n{i + 1} of {BmsDeviceCount}...");

                        await MaxDischargeAmpsRead(i, RegisterEnum.REG_DSGOC_DELAYS);

                        await Task.Delay(100);

                        if (_ObjBLEDevices[i].OverAmpTimeOutReadValue != NewOverAmpTimeOutValue)
                        {
                            isValid = false;
                            tCount++;
                        }
                        else
                        {
                            isValid = true;
                            break;
                        }
                    }
                }

                if (isValid)
                {
                    await ShowBusyindicatior(false);
                    await ShowDisplayPopup("Success", "");
                }
                else
                {
                    await ShowBusyindicatior(false);
                    await ShowDisplayPopup("NotSuccess", "");
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task MaxDischargeAmpsRead(int ModelIndex, string RegisterNumber = RegisterEnum.REG_DSGOC)
        {
            try
            {
                await SendWriteOrReadStartCommandToBMS(ModelIndex);

                await Task.Delay(100);

                // var getRegister29Value = new byte[] { 0xcc, 0xcb, 0x29, 0x00, 0xff, 0xd7, 0xcf };
                var getRegister29Value = _ObjProtocols[ModelIndex].CreateReadCommand(RegisterNumber);
                await SendCommandToBMS(getRegister29Value, ModelIndex);

                await Task.Delay(100);

                await SendWriteOrReadEndCommandToBMS(ModelIndex);

                await Task.Delay(1000);
            }
            catch (Exception ex)
            {
            }
        }

        // Heating & Balancing        
        private async void btnEnableSeriesBalanceUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                await ShowDisplayPopup("Information", "Keep the app running while charging and the SFK BMS app will attempt to balance your batteries.");

                await SendNotification("Battery Balance Started");

                bool ProceedForHeating = true;
                decimal BalActVoltage = 3.4M;
                decimal FloatCellVoltage = 3.3M;

                decimal ActivationVoltage = BalActVoltage * 4;
                decimal DeactivationVoltage = FloatCellVoltage * 4;

                while (ProceedForHeating)
                {
                    if (objMultiDeviceViewModel.arrTotalVoltes != null && objMultiDeviceViewModel.arrCaseTemp1 != null && objMultiDeviceViewModel.arrCaseTemp2 != null)
                    {
                        if (!objMultiDeviceViewModel.arrTotalVoltes.Any(x => x >= ActivationVoltage))
                        {
                            ProceedForHeating = false;
                            await SendNotification("Battery Balance Completed");
                            break;
                        }

                        decimal MinVoltage = objMultiDeviceViewModel.arrTotalVoltes.Min();
                        decimal MaxVoltage = objMultiDeviceViewModel.arrTotalVoltes.Max();
                        decimal VoltageDifference = MaxVoltage - MinVoltage;

                        for (int i = 0; i < objMultiDeviceViewModel.arrTotalVoltes.Length; i++)
                        {
                            decimal BatteryVoltage = objMultiDeviceViewModel.arrTotalVoltes[i];
                            decimal BatteryCaseTemp1 = objMultiDeviceViewModel.arrCaseTemp1[i];
                            decimal BatteryCaseTemp2 = objMultiDeviceViewModel.arrCaseTemp2[i];

                            if (IsFahrenheit)
                            {
                                BatteryCaseTemp1 = (BatteryCaseTemp1 - 32) * 5 / 9;
                                BatteryCaseTemp2 = (BatteryCaseTemp2 - 32) * 5 / 9; ;
                            }

                            if (BatteryVoltage > ActivationVoltage)
                            {
                                if (VoltageDifference > (30.0M / 1000.0M))
                                {
                                    if (BatteryVoltage > DeactivationVoltage)
                                    {
                                        if (BatteryCaseTemp1 <= BalanceTemperatureLimit && BatteryCaseTemp2 <= BalanceTemperatureLimit)
                                        {
                                            //Send Heating Command
                                            await SendHeatingPadsCommandToBMS(i);
                                            await Task.Delay(500);
                                        }
                                    }
                                }
                            }
                        }
                    }

                    await Task.Delay(5000);
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async void btnBalanceTempLimitUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                await ShowBusyindicatior(true);

                int NewLowTempValue = (int)rangesliderBalanceTempLimit.Value;

                switch (NewLowTempValue)
                {
                    case 104:
                        NewLowTempValue = 40;
                        break;
                    case 113:
