                BalanceTemperatureLimit = NewLowTempValue;

                UpdateToolTabValueinVirtualBattery();

                Preferences.Set("BalanceTemperatureLimitValue", Convert.ToInt32(NewLowTempValue));

                await ShowBusyindicatior(false);
                await ShowDisplayPopup("Success", "");
            }
            catch (Exception ex)
            {
            }
        }
        private async void btnActivationTempUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                bool bProcced = true;
                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    if (_ObjBLEDevices[i].Amps != decimal.Zero || _ObjBLEDevices[i].IsChargingOn != true || _ObjBLEDevices[i].IsDischargingOn != true)
                    {
                        bProcced = false;
                        break;
                    }
                }

                if (!bProcced && rdDisabledORLowTempProtectionOnly.IsChecked)
                {
                    await ShowDisplayPopup("Error", "Warning disabled heating mode should only be used in limited cases such as for testing. Some BMS functions will be disabled and integrations with Victron may not work properly.\nBattery must be in standby and discharging and charging must be enabled before switching heating modes.");
                }
                else
                {
                    isValidHeatingValue = false;
                    isHeatingBalanceUpdating = true;
                    for (int i = 0; i < BmsDeviceCount; i++)
                    {
                        await ShowBusyindicatior(true, $"Updating battery \n{i + 1} of {BmsDeviceCount}...");
                        if (isValidHeatingValue || i == 0)
                        {
                            await SendCommandForLowTempAndHeatingMode(i, true);
                        }
                        else
                        {
                            isHeatingBalanceUpdating = false;
                            await ShowBusyindicatior(false);
                            await ShowDisplayPopup("NotSuccess", "");
                            break;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task SendCommandForLowTempAndHeatingMode(int ModelIndex, bool SendHeatingModeCommand)
        {
            try
            {
                byte[] SendCommandE4 = new byte[0];
                int tCount = 0;
                bool IsValid = false;
                int NewLowTempValue = 0;
                string HeatingMode = string.Empty;

                if (SendHeatingModeCommand)
                {
                    NewLowTempValue = (int)rangesliderActivationTemp.Value;

                    if (rdLowTempcharging.IsChecked == true)
                    {
                        HeatingMode = "01";
                    }
                    else if (rdStandbyHeating.IsChecked == true)
                    {
                        HeatingMode = "02";
                    }
                    else if (rdDisabledORLowTempProtectionOnly.IsChecked == true)
                    {
                        HeatingMode = "00";
                    }
                }

                if (IsFahrenheit && NewLowTempValue < 35)
                {
                    NewLowTempValue = 35;
                }
                else if (!IsFahrenheit && NewLowTempValue < 1)
                {
                    NewLowTempValue = 1;
                }

                if (Convert.ToString(NewLowTempValue) == "35" || Convert.ToString(NewLowTempValue) == "1")
                {
                    while (tCount < 2) // Register 1a
                    {
                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 1); // 1°C ,35°F 
                        await SendCommandToBMS(setLowTempReg1a, ModelIndex);

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT);

                        if (_ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 1)
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if (_ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 1)
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1b
                        {
                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 4); // 4°C ,40°F
                            await SendCommandToBMS(setLowTempReg1b, ModelIndex);

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT_REL);

                            if (_ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 4)
                            {
                                tCount++;
                            }
                            else
                            {
                                IsValid = true;
                                break;
                            }
                        }
                    }

                    if (SendHeatingModeCommand)
                    {
                        SendCommandE4 = _ObjProtocols[ModelIndex].PrepareBytesForNewFirmwareStartAndStopTemp(1, 4, HeatingMode); // 35 , 40
                    }
                }
                else if (Convert.ToString(NewLowTempValue) == "40" || Convert.ToString(NewLowTempValue) == "4")
                {
                    while (tCount < 2) // Register 1a
                    {
                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        if (HeatingMode == "02")
                        {
                            NewLowTempValue = 1;
                            if (IsFahrenheit)
                            {
                                NewLowTempValue = 35;
                            }
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 1); // 1°C ,35°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }
                        else
                        {
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 4); // 4°C ,40°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT);

                        if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 4))
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 4))
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1b
                        {
                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            if (HeatingMode == "02")
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 4); // 4°C ,40°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }
                            else
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 7); // 7°C ,45°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT_REL);

                            if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 4) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 7))
                            {
                                tCount++;
                            }
                            else
                            {
                                IsValid = true;
                                break;
                            }
                        }
                    }

                    if (SendHeatingModeCommand)
                    {
                        SendCommandE4 = _ObjProtocols[ModelIndex].PrepareBytesForNewFirmwareStartAndStopTemp(4, 7, HeatingMode); // 40 , 45
                    }
                }
                else if (Convert.ToString(NewLowTempValue) == "45" || Convert.ToString(NewLowTempValue) == "7")
                {
                    while (tCount < 2) // Register 1a
                    {
                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);
                        if (HeatingMode == "02")
                        {
                            NewLowTempValue = 1;
                            if (IsFahrenheit)
                            {
                                NewLowTempValue = 35;
                            }
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 1); // 1°C ,35°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }
                        else
                        {
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 7); // 7°C ,45°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT);

                        if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 7))
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 7))
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1b
                        {
                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            if (HeatingMode == "02")
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 4); // 4°C ,40°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }
                            else
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 10); // 10°C ,50°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT_REL);

                            if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 4) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 10))
                            {
                                tCount++;
                            }
                            else
                            {
                                IsValid = true;
                                break;
                            }
                        }
                    }

                    if (SendHeatingModeCommand)
                    {
                        SendCommandE4 = _ObjProtocols[ModelIndex].PrepareBytesForNewFirmwareStartAndStopTemp(7, 10, HeatingMode); //45 , 50                        
                    }
                }
                else if (Convert.ToString(NewLowTempValue) == "50" || Convert.ToString(NewLowTempValue) == "10")
                {
                    while (tCount < 2) // Register 1a
                    {
                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        if (HeatingMode == "02")
                        {
                            NewLowTempValue = 1;
                            if (IsFahrenheit)
                            {
                                NewLowTempValue = 35;
                            }
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 1); // 1°C ,35°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }
                        else
                        {
                            var setLowTempReg1a = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT, 10); // 10°C ,50°F
                            await SendCommandToBMS(setLowTempReg1a, ModelIndex);
                        }

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT);

                        if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 10))
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 1) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue == 10))
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1b
                        {
                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            if (HeatingMode == "02")
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 4); // 4°C ,40°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }
                            else
                            {
                                var setLowTempReg1b = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_CHGUT_REL, 13); // 13°C ,55°F
                                await SendCommandToBMS(setLowTempReg1b, ModelIndex);
                            }

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT_REL);

                            if ((HeatingMode == "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 4) || (HeatingMode != "02" && _ObjBLEDevices[ModelIndex].IsvalidLowTempValue != 13))
                            {
                                tCount++;
                            }
                            else
                            {
                                IsValid = true;
                                break;
                            }
                        }
                    }

                    if (SendHeatingModeCommand)
                    {
                        SendCommandE4 = _ObjProtocols[ModelIndex].PrepareBytesForNewFirmwareStartAndStopTemp(10, 13, HeatingMode);  //50 , 55                        
                    }
                }

                if (SendHeatingModeCommand)
                {
                    await SendWriteOrReadStartCommandToBMS(ModelIndex);

                    await Task.Delay(100);

                    await SendCommandToBMS(SendCommandE4, ModelIndex);

                    await Task.Delay(100);

                    await SendWriteOrReadEndCommandToBMS(ModelIndex);

                    await Task.Delay(1000);

                    await ReadSOCAndHeatingMode(ModelIndex);

                    await Task.Delay(100);
                }

                if (IsValid && _ObjBLEDevices[ModelIndex].LowTempValue == NewLowTempValue && (!SendHeatingModeCommand || _ObjBLEDevices[ModelIndex].HeatingModeValue == Convert.ToInt32(HeatingMode)))
                {
                    isValidHeatingValue = true;
                }
                else
                {
                    isValidHeatingValue = false;
                }

                if (ModelIndex == (BmsDeviceCount - 1))
                {
                    isHeatingBalanceUpdating = false;
                    if (isValidHeatingValue)
                    {
                        await ChargingUnderTempRead(ModelIndex, RegisterEnum.REG_CHGUT);

                        await ShowBusyindicatior(false);
                        await ShowDisplayPopup("Success", "");
                    }
                    else
                    {
                        await ShowBusyindicatior(false);
                        await ShowDisplayPopup("NotSuccess", "");
                    }
                }
            }
            catch (Exception ex)
            {

            }
        }
        private async void RadioButtonGroupViewHeatingModes_Tapped(object sender, TappedEventArgs e)
        {
            try
            {
                InputKit.Shared.Controls.RadioButton objRadioButton = (InputKit.Shared.Controls.RadioButton)sender;
                await SetLowTempHeatingMode(Convert.ToInt32(objRadioButton.ClassId));

                string strData = string.Empty;
                if (objRadioButton.ClassId == "0")
                {
                    strData = "DisabledHeatingRadio_" + objRadioButton.IsChecked;
                }
                else if (objRadioButton.ClassId == "1")
                {
                    strData = "LowTempHeatingRadio_" + objRadioButton.IsChecked;
                }
                else if (objRadioButton.ClassId == "2")
                {
                    strData = "StandbyHeatingRadio_" + objRadioButton.IsChecked;
                }
                await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.RadioButtonValueChange, strData);
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task SetLowTempHeatingMode(int HeatingMode)
        {
            try
            {
                if (HeatingMode == 1 || HeatingMode == 01)
                {
                    if (IsFahrenheit)
                    {
                        rangesliderActivationTemp.Minimum = 35;
                        rangesliderActivationTemp.Maximum = 45;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 5;
                    }
                    else
                    {
                        rangesliderActivationTemp.Minimum = 1;
                        rangesliderActivationTemp.Maximum = 7;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 3;
                    }

                    if (TempsliderLowTempValue == 10 || TempsliderLowTempValue == 50)
                    {
                        if (IsFahrenheit)
                        {
                            rangesliderActivationTemp.Value = 45;
                        }
                        else
                        {
                            rangesliderActivationTemp.Value = 7;
                        }
                    }
                    else
                    {
                        rangesliderActivationTemp.Value = TempsliderLowTempValue;
                    }
                }
                else if (HeatingMode == 2 || HeatingMode == 02)
                {
                    if (IsFahrenheit)
                    {
                        rangesliderActivationTemp.Minimum = 40;
                        rangesliderActivationTemp.Maximum = 50;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 5;
                    }
                    else
                    {
                        rangesliderActivationTemp.Minimum = 4;
                        rangesliderActivationTemp.Maximum = 10;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 3;
                    }

                    if (TempsliderLowTempValue == 1 || TempsliderLowTempValue == 35)
                    {
                        if (IsFahrenheit)
                        {
                            rangesliderActivationTemp.Value = 40;
                        }
                        else
                        {
                            rangesliderActivationTemp.Value = 4;
                        }
                    }
                    else
                    {
                        rangesliderActivationTemp.Value = TempsliderLowTempValue;
                    }
                }
                else if (HeatingMode == 0 || HeatingMode == 00)
                {
                    if (IsFahrenheit)
                    {
                        rangesliderActivationTemp.Minimum = 35;
                        rangesliderActivationTemp.Maximum = 45;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 5;
                    }
                    else
                    {
                        rangesliderActivationTemp.Minimum = 1;
                        rangesliderActivationTemp.Maximum = 7;
                        rangesliderActivationTemp.Interval = rangesliderActivationTemp.StepSize = 3;
                    }

                    if (TempsliderLowTempValue == 10 || TempsliderLowTempValue == 50)
                    {
                        if (IsFahrenheit)
                        {
                            rangesliderActivationTemp.Value = 45;
                        }
                        else
                        {
                            rangesliderActivationTemp.Value = 7;
                        }
                    }
                    else
                    {
                        rangesliderActivationTemp.Value = TempsliderLowTempValue;
                    }
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async void btnLowTempDischargingUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                await ShowBusyindicatior(true);

                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    await ShowBusyindicatior(true, $"Updating battery \n{i + 1} of {BmsDeviceCount}...");

                    await LowTempDischarging(i);
