                    Preferences.Set("LowTempDischarge", Convert.ToString(CheckBoxLowTempDischarg.IsChecked));

                    await ShowDisplayPopup("Success", "");
                }
                else
                {
                    await ShowBusyindicatior(false);
                    await ShowDisplayPopup("NotSuccess", "");

                    CheckBoxLowTempDischarg.IsChecked = !CheckBoxLowTempDischarg.IsChecked;
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task LowTempDischarging(int ModelIndex)
        {
            try
            {
                int tCount = 0;

                int TempratureValue = 0;

                if (CheckBoxLowTempDischarg.IsChecked)
                {
                    // Discharge Under Temp
                    while (tCount < 2) // Register 1e
                    {
                        TempratureValue = -20;

                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        // var setLowTempDischargeReg1e = new byte[] { 0xdd, 0x5a, 0x1e, 0x02, 0x09, 0xe4, 0xfe, 0xf3, 0x77 }; //-20
                        var setLowTempDischargeReg1e = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_DSGUT, -20);
                        await SendCommandToBMS(setLowTempDischargeReg1e, ModelIndex);

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await LowTempDischargeRead(ModelIndex, RegisterEnum.REG_DSGUT);

                        if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue != TempratureValue)
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue == TempratureValue)
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1f
                        {
                            TempratureValue = -15;

                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            // var setLowTempDischargeReg1f = new byte[] { 0xdd, 0x5a, 0x1f, 0x02, 0x0a, 0x16, 0xff, 0xbf, 0x77 }; // -15
                            var setLowTempDischargeReg1f = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_DSGUT_REL, -15);
                            await SendCommandToBMS(setLowTempDischargeReg1f, ModelIndex);

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await LowTempDischargeRead(ModelIndex, RegisterEnum.REG_DSGUT_REL);

                            if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue != TempratureValue)
                            {
                                tCount++;
                            }
                            else
                            {
                                IsLowTempDischarging = true;
                                break;
                            }
                        }
                    }
                }
                else if (!CheckBoxLowTempDischarg.IsChecked)
                {
                    // Discharge Under Temp
                    while (tCount < 2) // Register 1e
                    {
                        TempratureValue = -1;

                        await SendWriteOrReadStartCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        // var setLowTempDischargeReg1e = new byte[] { 0xdd, 0x5a, 0x1e, 0x02, 0x0a, 0xa2, 0xff, 0x34, 0x77 }; //-1
                        var setLowTempDischargeReg1e = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_DSGUT, -1);
                        await SendCommandToBMS(setLowTempDischargeReg1e, ModelIndex);

                        await Task.Delay(100);

                        await SendWriteOrReadEndCommandToBMS(ModelIndex);

                        await Task.Delay(100);

                        await LowTempDischargeRead(ModelIndex, RegisterEnum.REG_DSGUT);

                        if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue != TempratureValue)
                        {
                            tCount++;
                        }
                        else
                        {
                            break;
                        }
                    }

                    if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue == TempratureValue)
                    {
                        tCount = 0;
                        while (tCount < 2) // Register 1f
                        {
                            TempratureValue = 2;

                            await SendWriteOrReadStartCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            // var setLowTempDischargeReg1f = new byte[] { 0xdd, 0x5a, 0x1f, 0x02, 0x0a, 0xc0, 0xff, 0x15, 0x77 }; //2
                            var setLowTempDischargeReg1f = _ObjProtocols[ModelIndex].CreateTempratureByte(RegisterEnum.REG_DSGUT_REL, 2);
                            await SendCommandToBMS(setLowTempDischargeReg1f, ModelIndex);

                            await Task.Delay(100);

                            await SendWriteOrReadEndCommandToBMS(ModelIndex);

                            await Task.Delay(100);

                            await LowTempDischargeRead(ModelIndex, RegisterEnum.REG_DSGUT_REL);

                            if (_ObjBLEDevices[ModelIndex].IsValidLowTempDischargeValue != TempratureValue)
                            {
                                tCount++;
                            }
                            else
                            {
                                IsLowTempDischarging = true;
                                break;
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task LowTempDischargeRead(int ModelIndex, string RegisterNumber = "1c")
        {
            try
            {
                await SendWriteOrReadStartCommandToBMS(ModelIndex);

                await Task.Delay(100);

                var byteValue = _ObjProtocols[ModelIndex].CreateReadCommand(RegisterNumber);
                await SendCommandToBMS(byteValue, ModelIndex);

                await Task.Delay(1000);
            }
            catch (Exception ex)
            {
            }
        }
        private async void btnPullRequestUpdate_Clicked(object sender, EventArgs e)
        {
            try
            {
                await ShowBusyindicatior(true);

                if (rdPulllRequestOne.IsChecked == true)
                {
                    Preferences.Set("PollRequestData", "1000");
                    PullingRequestTime = 1000;
                }
                else if (rdPulllRequestTwo.IsChecked == true)
                {
                    Preferences.Set("PollRequestData", "2000");
                    PullingRequestTime = 2000;
                }
                else if (rdPulllRequestThree.IsChecked == true)
                {
                    Preferences.Set("PollRequestData", "3000");
                    PullingRequestTime = 3000;
                }

                await Task.Delay(500);

                await btnPullRequestRead();

                RunMainPageWhileLoop = false;

                await Task.Delay(100);

                if (_Executioncts != null)
                {
                    _Executioncts.Cancel();
                    _Executioncts.Dispose();
                    _Executioncts = null;
                }

                await ShowBusyindicatior(false);

                await ShowDisplayPopup("Success", "");

                await StartExecution();
            }
            catch (Exception ex)
            {
                await ShowBusyindicatior(false);
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }

