        #region Read Tool tab Values
        private async Task LoadToolTabForReadingData()
        {
            try
            {
                if (!IsPageFirstTimeLoading)
                {
                    isTooTabLoading = true;

                    await ShowAbsoluteLayout(true, "", true);

                    stackHeatingBalancing.IsVisible = EnableHeatingAndSeriesBalance;

                    if (SettingValue != "Parallel")
                    {
                        stackOnlyForSeries.IsVisible = true;
                    }

                    bool allSameValue = true;
                    for (int i = 0; i < BmsDeviceCount; i++)
                    {
                        await MaxDischargeAmpsRead(i, RegisterEnum.REG_DSGOC_DELAYS);

                        await LowTempDischargeRead(i, RegisterEnum.REG_DSGUT);

                        await ReadSOCAndHeatingMode(i);

                        await ChargingUnderTempRead(i, RegisterEnum.REG_CHGUT);

                        if (!string.IsNullOrWhiteSpace(_ObjBLEDevices[i].DeviceName) && _ObjBLEDevices[0].HeatingModeValue != _ObjBLEDevices[i].HeatingModeValue)
                        {
                            allSameValue = false;
                        }
                    }

                    if (allSameValue)
                    {
                        HeatingMode = _ObjBLEDevices[0].HeatingModeValue;
                        if (HeatingMode == 1 || HeatingMode == 01)
                        {
                            rdLowTempcharging.IsChecked = true;
                        }
                        else if (HeatingMode == 2 || HeatingMode == 02)
                        {
                            rdStandbyHeating.IsChecked = true;
                        }
                        else if (HeatingMode == 0 || HeatingMode == 00)
                        {
                            rdDisabledORLowTempProtectionOnly.IsChecked = true;
                        }
                    }
                    else
                    {
                        HeatingMode = 2;
                        rdStandbyHeating.IsChecked = true;
                    }

                    await SetLowTempHeatingMode(HeatingMode);

                    List<int> lstOverAmpTimeOut = _ObjBLEDevices.Select(d => d.OverAmpTimeOutReadValue).Where(m => m > 0).Distinct().ToList();
                    if (lstOverAmpTimeOut.Count() > 0)
                    {
                        rangesliderOverAmpTimeOut.Value = lstOverAmpTimeOut.Min();
                    }

                    List<double> lstLowTempDischargeValue = _ObjBLEDevices.Select(d => d.IsValidLowTempDischargeValue).Where(m => m != 0).Distinct().ToList();
                    if (lstLowTempDischargeValue.Count() == 1)
                    {
                        if (lstLowTempDischargeValue[0] == -20)
                        {
                            CheckBoxLowTempDischarg.IsChecked = true;
                        }
                        else if (lstLowTempDischargeValue[0] == -1)
                        {
                            CheckBoxLowTempDischarg.IsChecked = false;
                        }
                    }
                    else if (lstLowTempDischargeValue.Count() > 1)
                    {
                        CheckBoxLowTempDischarg.IsChecked = false;
                    }
                }

                ToolTabValueRead();

                UpdateVirtualBatteryList();

                if (!IsPageFirstTimeLoading)
                {
                    isTooTabLoading = false;
                    await ShowAbsoluteLayout(false, "", true);
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task btnTemperatureUnitRead()
        {
            try
            {
                var _Temp = Preferences.Get("CelsiusorFahrenheitMulti", string.Empty);

                sCelsiusorFahrenheit = Convert.ToString(_Temp);


                if (sCelsiusorFahrenheit == "" || sCelsiusorFahrenheit == null)
                {
                    Preferences.Set("CelsiusorFahrenheitMulti", "Fahrenheit");

                    _Temp = Preferences.Get("CelsiusorFahrenheitMulti", string.Empty);
                    sCelsiusorFahrenheit = Convert.ToString(_Temp);
                }

                RadioButtonViewModel _ObjRadioButtonViewModel = new RadioButtonViewModel();
                _ObjRadioButtonViewModel.TemperatureUnit = new bool[2];

                if (sCelsiusorFahrenheit == "Celsius")
                {
                    _ObjRadioButtonViewModel.TemperatureUnit[0] = true;
                    _ObjRadioButtonViewModel.TemperatureUnit[1] = false;

                    IsFahrenheit = false;
                }
                else if (sCelsiusorFahrenheit == "Fahrenheit")
                {
                    _ObjRadioButtonViewModel.TemperatureUnit[0] = false;
                    _ObjRadioButtonViewModel.TemperatureUnit[1] = true;

                    IsFahrenheit = true;
                }

                rdCelsius.BindingContext = _ObjRadioButtonViewModel;
                rdCelsius.IsChecked = _ObjRadioButtonViewModel.TemperatureUnit[0];

                rdFahrenheit.BindingContext = _ObjRadioButtonViewModel;
                rdFahrenheit.IsChecked = _ObjRadioButtonViewModel.TemperatureUnit[1];

                for (int i = 0; i < BmsDeviceCount; i++)
                {
                    if (UsedNewFirmwareDevices[i])
                    {
                        await ChargingUnderTempRead(i);
                    }
                }

                await CelsiusorFahrenheit();
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task CelsiusorFahrenheit()
        {
            try
            {
                if (IsFahrenheit)
                {
                    rangesliderBalanceTempLimit.BindingContext = _ObjDeviceInformations[0];
                    rangesliderBalanceTempLimit.Minimum = _ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimit[0].Value;
                    rangesliderBalanceTempLimit.Maximum = _ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimit[_ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimit.Count - 1].Value;
                    rangesliderBalanceTempLimit.Interval = rangesliderBalanceTempLimit.StepSize = 9;
                }
                else
                {
                    rangesliderBalanceTempLimit.BindingContext = _ObjDeviceInformations[0];
                    rangesliderBalanceTempLimit.Minimum = _ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimitCelsius[0].Value;
                    rangesliderBalanceTempLimit.Maximum = _ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimitCelsius[_ObjDeviceInformations[0].CustomCollectionBalanceTemperatureLimitCelsius.Count - 1].Value;
                    rangesliderBalanceTempLimit.Interval = rangesliderBalanceTempLimit.StepSize = 5;
                }
            }
            catch (Exception ex)
            {
            }
        }
