        private async Task ChargingUnderTempRead(int ModelIndex, string RegisterNumber = RegisterEnum.REG_CHGUT_REL)
        {
            var byteValue = new byte[10];
            try
            {
                await SendWriteOrReadStartCommandToBMS(ModelIndex);

                await Task.Delay(100);

                byteValue = _ObjProtocols[ModelIndex].CreateReadCommand(RegisterNumber);

                await SendCommandToBMS(byteValue, ModelIndex);

                await Task.Delay(100);

                await SendWriteOrReadEndCommandToBMS(ModelIndex);

                await Task.Delay(1000);
            }
            catch (Exception ex)
            {

            }
        }
        private async void ddlvirtualbattry_SelectionChanged(object sender, Syncfusion.Maui.Inputs.SelectionChangedEventArgs e)
        {
            try
            {
                List<string> VirtualBatteryList = new List<string>();
                string sVirtualBattery = Preferences.Get("VirtualBatteryList", string.Empty);

                if (!string.IsNullOrWhiteSpace(sVirtualBattery))
                {
                    if (sVirtualBattery.Contains(","))
                    {
                        VirtualBatteryList = sVirtualBattery.Split(',').ToList();
                    }
                    else
                    {
                        VirtualBatteryList.Add(sVirtualBattery);
                    }
                }
                VirualBattery objVirualBattery = e.CurrentSelection.FirstOrDefault() as VirualBattery;
                if (objVirualBattery != null)
                {
                    if (objVirualBattery.Name.ToString().ToLower().Trim().Contains("select"))
                    {
                        chkAutomaticallyConnect.IsEnabled = false;
                        chkAutomaticallyConnect.IsDisabled = true;
                        chkAutomaticallyConnect.IsChecked = false;
                        btnDeleteVirtualBattery.IsEnabled = false;
                        chkAutomaticallyConnect.BorderColor = Colors.Gray;
                        btnDeleteVirtualBattery.BackgroundColor = Color.FromHex("#808080");
                    }
                    else
                    {
                        CurrentSelectedVirtualBattery = objVirualBattery.Name.ToString();
                        VB_SelectedValue = CurrentSelectedVirtualBattery;
                        for (int i = 0; i < VirtualBatteryList.Count; i++)
                        {
                            string Name = Convert.ToString(VirtualBatteryList[i].Remove(VirtualBatteryList[i].IndexOf('_')));
                            if (objVirualBattery.Name.ToString().ToLower().Trim() == Name.ToString().ToLower().Trim())
                            {
                                bool Checked = Convert.ToBoolean(VirtualBatteryList[i].Substring(VirtualBatteryList[i].IndexOf('_') + 1));
                                if (Checked)
                                {
                                    chkAutomaticallyConnect.IsChecked = true;
                                }
                                else
                                {
                                    chkAutomaticallyConnect.IsChecked = false;
                                }
                            }
                        }

                        chkAutomaticallyConnect.IsEnabled = true;
                        chkAutomaticallyConnect.IsDisabled = false;
                        chkAutomaticallyConnect.BorderColor = Color.FromHex("#fc0");
                        btnDeleteVirtualBattery.BackgroundColor = Colors.Red;
                        btnDeleteVirtualBattery.IsEnabled = true;
                    }
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async void btnDeleteVirtualBattery_Clicked(object sender, EventArgs e)
        {
            try
            {
                string deleteVirtualBattery = string.Empty;

                string sVirtualBattery = Preferences.Get("VirtualBatteryList", string.Empty);

                string selectedVirtualBattery = VB_SelectedValue;

                if (!DeleteVirtualBattery)
                {
                    await ShowDisplayPopup("ComfirmationPopUpDeleteVBattery", "Are you sure, you want to Delete This '" + selectedVirtualBattery + "' Virtual Battery");
                }

                if (DeleteVirtualBattery)
                {
                    if (!string.IsNullOrWhiteSpace(selectedVirtualBattery) && !string.IsNullOrWhiteSpace(sVirtualBattery))
                    {
                        if (sVirtualBattery.Contains(selectedVirtualBattery + "_true"))
                        {
                            deleteVirtualBattery = selectedVirtualBattery + "_true";
                        }
                        else
                        {
                            deleteVirtualBattery = selectedVirtualBattery + "_false";
                        }


                        if (sVirtualBattery.Contains(",") && !(sVirtualBattery.EndsWith(deleteVirtualBattery)))
                        {
                            sVirtualBattery = sVirtualBattery.Replace(deleteVirtualBattery + ",", "");
                        }
                        else
                        {
                            sVirtualBattery = sVirtualBattery.Replace(deleteVirtualBattery, "");
                        }

                        if (sVirtualBattery.EndsWith(","))
                        {
                            sVirtualBattery = sVirtualBattery.Remove(sVirtualBattery.Length - 1);
                        }
                    }

                    Preferences.Set("VirtualBatteryList", sVirtualBattery);

                    await UpdateVirtualBatteryList();

                    await ShowDisplayPopup("Success", "The selected virtual battery has been successfully deleted.");

                    DeleteVirtualBattery = false;
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async void btnUpdateVirtualBattery_Clicked(object sender, EventArgs e)
        {
            try
            {
                string sVirtualBattery = Preferences.Get("VirtualBatteryList", string.Empty);

                if (!string.IsNullOrWhiteSpace(CurrentSelectedVirtualBattery) && !CurrentSelectedVirtualBattery.ToString().ToLower().Trim().Contains("select") && !string.IsNullOrWhiteSpace(sVirtualBattery))
                {
                    if (chkAutomaticallyConnect.IsChecked)
                    {
                        sVirtualBattery = sVirtualBattery.Replace("true", "false");
                        sVirtualBattery = sVirtualBattery.Replace(CurrentSelectedVirtualBattery + "_" + Convert.ToString(!chkAutomaticallyConnect.IsChecked).ToLower(), CurrentSelectedVirtualBattery + "_" + Convert.ToString(chkAutomaticallyConnect.IsChecked).ToLower());
                    }
                    else
                    {
                        sVirtualBattery = sVirtualBattery.Replace(CurrentSelectedVirtualBattery + "_" + Convert.ToString(!chkAutomaticallyConnect.IsChecked).ToLower(), CurrentSelectedVirtualBattery + "_" + Convert.ToString(chkAutomaticallyConnect.IsChecked).ToLower());
                    }

                    Preferences.Set("VirtualBatteryList", sVirtualBattery);

                    await UpdateVirtualBattery(CurrentSelectedVirtualBattery, sVirtualBattery);

                    await UpdateVirtualBatteryList();

                    await ShowDisplayPopup("Success", "Virtual battery settings have been updated.");
                }
                else
                {
                    await ShowDisplayPopup("Success", "Please select virtual battery.");
                }
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async void btnCreateVirtualbatteryName_Clicked(object sender, EventArgs e)
        {
            try
            {
                string BatterySetupSetting = string.Empty;
