                    string VirtualBatteryName = string.Empty;
                    if (!string.IsNullOrWhiteSpace(sVirtualBattery))
                    {
                        if (sVirtualBattery.Contains(","))
                        {
                            VirtualBatteryList = sVirtualBattery.Split(',').ToList();
                        }
                        else
                        {
                            VirtualBatteryList.Add(sVirtualBattery);
                        }

                        for (int i = 0; i < VirtualBatteryList.Count; i++)
                        {
                            VirtualBatteryName = VirtualBatteryList[i].Remove(VirtualBatteryList[i].IndexOf('_'));
                            if (VirtualBatteryName == txtVirtualBattryname.Text)
