        private async Task ToolTabValueRead()
        {
            try
            {
                var AmpsDrawValue = Preferences.Get("AmpsDrawValue", string.Empty);
                var VoltsDrawValue = Preferences.Get("VoltsDrawValue", string.Empty);
                SpeedUnitValue = Preferences.Get("SpeedUnitValue", string.Empty);
                PowerUnitValue = Preferences.Get("PowerUnitValue", string.Empty);

                var BalanceTemperatureLimitValue = Preferences.Get("BalanceTemperatureLimitValue", 0);

                if (BalanceTemperatureLimitValue > 0)
                {
                    BalanceTemperatureLimit = Convert.ToInt32(BalanceTemperatureLimitValue);
                    if (IsFahrenheit)
                    {
                        BalanceTemperatureLimitValue = (BalanceTemperatureLimitValue - 32) * 5 / 9;
                    }
                    rangesliderBalanceTempLimit.Value = Convert.ToInt32(BalanceTemperatureLimitValue);
                }
                else
                {
                    BalanceTemperatureLimit = 45;
                    rangesliderBalanceTempLimit.Value = 113;
                }

                #region AmpsDraw

                if (!string.IsNullOrWhiteSpace(AmpsDrawValue))
                {
                    if (AmpsDrawValue == "N/A")
                    {
                        rangesliderAmpsDraw.Value = 3;
                        AmpsDrawWarning = 3;
                    }
                    else
                    {
                        rangesliderAmpsDraw.Value = Convert.ToDouble(AmpsDrawValue);
                        AmpsDrawWarning = Convert.ToDecimal(AmpsDrawValue);
                    }
                }
                else
                {
                    Preferences.Set("AmpsDrawValue", "N/A");
                    rangesliderAmpsDraw.Value = 3;
                    AmpsDrawWarning = 3;
                }

                #endregion AmpsDraw

                #region VoltsDraw
                if (!string.IsNullOrWhiteSpace(VoltsDrawValue))
                {
                    if (VoltsDrawValue == "N/A")
                    {
                        rangesliderVoltsDraw.Value = 0.15;
                        VoltsDrawWarning = 0.15M;
                    }
                    else
                    {
                        rangesliderVoltsDraw.Value = Convert.ToDouble(VoltsDrawValue);
                        VoltsDrawWarning = Convert.ToDecimal(VoltsDrawValue);
                    }
                }
                else
                {
                    Preferences.Set("VoltsDrawValue", "N/A");
                    VoltsDrawWarning = 0.15M;
                }

                #endregion VoltsDraw

                #region AutoDashboard

                //Speed Unit
                if (!string.IsNullOrWhiteSpace(SpeedUnitValue))
                {
                    stackkph.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblkph.TextColor = Color.FromArgb("#818181");
                    stackmph.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblmph.TextColor = Color.FromArgb("#818181");
                    if (SpeedUnitValue == "mph")
                    {
                        stackmph.BackgroundColor = Color.FromArgb("#F26D24");
                        lblmph.TextColor = Color.FromArgb("#FFFFFF");
                    }
                    else
                    {
                        stackkph.BackgroundColor = Color.FromArgb("#F26D24");
                        lblkph.TextColor = Color.FromArgb("#FFFFFF");
                    }
                    lblAutoSpeedType.Text = SpeedUnitValue;
                }
                else
                {
                    stackmph.BackgroundColor = Color.FromArgb("#F26D24");
                    lblmph.TextColor = Color.FromArgb("#FFFFFF");
                    Preferences.Set("SpeedUnitValue", "mph");
                }


                //Power Unit
                if (!string.IsNullOrWhiteSpace(PowerUnitValue))
                {
                    stackkW.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblkW.TextColor = Color.FromArgb("#818181");
                    stackAmp.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblAmp.TextColor = Color.FromArgb("#818181");
                    stackhp.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblhp.TextColor = Color.FromArgb("#818181");
                    if (PowerUnitValue == "kW")
                    {
                        stackkW.BackgroundColor = Color.FromArgb("#008000");
                        lblkW.TextColor = Color.FromArgb("#FFFFFF");
                    }
                    else if (PowerUnitValue == "amp")
                    {
                        stackAmp.BackgroundColor = Color.FromArgb("#008000");
                        lblAmp.TextColor = Color.FromArgb("#FFFFFF");
                    }
                    else if (PowerUnitValue == "hp")
                    {
                        stackhp.BackgroundColor = Color.FromArgb("#008000");
                        lblhp.TextColor = Color.FromArgb("#FFFFFF");
                    }
                    lblAutoPowerType.Text = PowerUnitValue;
                }
                else
                {
                    stackkW.BackgroundColor = Color.FromArgb("#008000");
                    lblkW.TextColor = Color.FromArgb("#FFFFFF");
                    Preferences.Set("PowerUnitValue", "kW");
                }

                #endregion AutoDashboard                                
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task ReadDaySinceFullCharge(int ModelIndex, string command = "days")
        {
            try
            {
                if (command == "days")
                {
                    await SendWriteOrReadStartCommandToBMS(ModelIndex);

                    await Task.Delay(100);

                    // CC F1 03 01 FF FC CF
                    var byteValue = _ObjProtocols[ModelIndex].CreateH2CustomCommand(RegisterEnum.REG_SINCE_FULL, "03", 1);
                    await SendCommandToBMS(byteValue, ModelIndex);

                    await Task.Delay(100);

                    await SendWriteOrReadEndCommandToBMS(ModelIndex);
                }
                else if (command == "date")
                {
                    await SendWriteOrReadStartCommandToBMS(ModelIndex);

                    await Task.Delay(100);

                    // CC F1 03 01 FF FC CF
                    var byteValue = _ObjProtocols[ModelIndex].CreateH2CustomCommand(RegisterEnum.DAY_SINCE_DATE, "03", 1);
                    await SendCommandToBMS(byteValue, ModelIndex);

                    await Task.Delay(100);

                    await SendWriteOrReadEndCommandToBMS(ModelIndex);
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task btnPullRequestRead()
        {
            try
            {
                var _Temp = Preferences.Get("PollRequestData", string.Empty);
                int.TryParse(_Temp, out PullingRequestTime);

                if (PullingRequestTime == 0)
                {
                    Preferences.Set("PollRequestData", "3000");
                    PullingRequestTime = 3000;
                }

                objRadioButtonViewModel = new RadioButtonViewModel();
                objRadioButtonViewModel.PullRequestData = new bool[3];

                if (PullingRequestTime == 1000)
                {
                    objRadioButtonViewModel.PullRequestData[0] = true;
                    objRadioButtonViewModel.PullRequestData[1] = false;
                    objRadioButtonViewModel.PullRequestData[2] = false;
                }
                else if (PullingRequestTime == 2000)
                {
                    objRadioButtonViewModel.PullRequestData[0] = false;
                    objRadioButtonViewModel.PullRequestData[1] = true;
                    objRadioButtonViewModel.PullRequestData[2] = false;
                }
                else if (PullingRequestTime == 3000)
                {
                    objRadioButtonViewModel.PullRequestData[0] = false;
                    objRadioButtonViewModel.PullRequestData[1] = false;
                    objRadioButtonViewModel.PullRequestData[2] = true;
                }

                rdPulllRequestOne.BindingContext = objRadioButtonViewModel;
                rdPulllRequestOne.IsChecked = objRadioButtonViewModel.PullRequestData[0];

                rdPulllRequestTwo.BindingContext = objRadioButtonViewModel;
                rdPulllRequestTwo.IsChecked = objRadioButtonViewModel.PullRequestData[1];

                rdPulllRequestThree.BindingContext = objRadioButtonViewModel;
                rdPulllRequestThree.IsChecked = objRadioButtonViewModel.PullRequestData[2];

                await Task.Delay(1000);
            }
            catch (Exception ex)
            {
                if (nWriteCounter < EstablishConnectionDatAttemps)
                {
                    nWriteCounter++;
                }
            }
        }
        private async Task UpdateVirtualBattery(string CurrentSelectedVirtualBattery = "", string sVirtualBattery = "")
        {
            try
            {
                string BatterySetupSetting = string.Empty;
                string MacAddress = string.Empty;
                string strVirtualBatteryValue = string.Empty;
                bool bVirtualBatteryExist = false;
                await ShowBusyindicatior(true);
                // string sVirtualBattery = Preferences.Get("VirtualBatteryList", string.Empty);

                if (!string.IsNullOrWhiteSpace(CurrentSelectedVirtualBattery))
                {
                    List<string> VirtualBatteryList = new List<string>();
                    string VirtualBatteryName = string.Empty;
                    if (!string.IsNullOrWhiteSpace(sVirtualBattery))
                    {
                        VirtualBatteryList = sVirtualBattery.Split(',').ToList();
                        for (int i = 0; i < VirtualBatteryList.Count; i++)
                        {
                            VirtualBatteryName = VirtualBatteryList[i].Remove(VirtualBatteryList[i].IndexOf('_'));
                            if (VirtualBatteryName == CurrentSelectedVirtualBattery)
                            {
                                bVirtualBatteryExist = true;
                                break;
                            }
                        }
                    }

                    if (bVirtualBatteryExist)
                    {
                        lblErrorMassage.IsVisible = false;

                        if (BmsDeviceCount == 2)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforTwo";
                        }
                        else if (BmsDeviceCount == 3)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforThree";
                        }
                        else if (BmsDeviceCount == 4)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforFour";
                        }
                        else if (BmsDeviceCount == 5)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforFive";
                        }
                        else if (BmsDeviceCount == 6)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforSix";
                        }
                        else if (BmsDeviceCount == 7)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforSeven";
                        }
                        else if (BmsDeviceCount == 8)
                        {
                            BatterySetupSetting = "BatteryConnectionSetupforEight";
                        }

                        strVirtualBatteryValue = Preferences.Get(BatterySetupSetting, string.Empty);

                        strVirtualBatteryValue = strVirtualBatteryValue + "|" + AmpsDrawWarning + "|" + VoltsDrawWarning + "|" + BalanceTemperatureLimit + "|" + LowTempActivation + "|" + HeatingMode;

                        for (int i = 0; i < BmsDeviceCount; i++)
                        {
                            MacAddress = _ConnectedDevices[i].MacAddress;
                            strVirtualBatteryValue += "|" + MacAddress;
                        }

                        Preferences.Set(CurrentSelectedVirtualBattery.Trim(), strVirtualBatteryValue);
                    }
                    else
                    {
                        await ShowDisplayPopup("Error", "A virtual battery with this name already exists. Please choose a different name.");
                    }
                }
                else
                {
                    lblErrorMassage.IsVisible = true;
                }

                await ShowBusyindicatior(false);
            }
            catch (Exception ex)
            {
            }
        }
