        private async Task<bool> GetBMSConnectionStatus()
        {
            bool BMSConnectionStatus = false;
            try
            {
                await RemoteSessionDetails.SendDataToRemoteSession(RemoteSessionSendCommandTypes.CheckDeviceConnectionStatus, null);

                ResponceCount = 0;
                while (ResponceCount < 30)
                {
                    await Task.Delay(1000);
                    if (IsDeviceConnectionStatus)
                    {
                        break;
                    }
                    ResponceCount++;
                }

                BMSConnectionStatus = IsDeviceConnectionStatus;
            }
            catch { }

            return BMSConnectionStatus;
        }
