        #region GPS Speed 
        private CancellationTokenSource _cts;
        private PeriodicTimer timer;
        private bool _isTimerRunning = false;
        private bool _isTrackingRunning = false;
        private Task _gpsFlashTask;
        private double _lastValidSpeed = 0;
        private DateTime _lastSpeedTime = DateTime.MinValue;

        private async Task CheckAndRequestLocationPermission()
        {
            try
            {
                var status = await Permissions.CheckStatusAsync<Permissions.LocationWhenInUse>();

                if (status != PermissionStatus.Granted)
                {
                    status = await Permissions.RequestAsync<Permissions.LocationWhenInUse>();
                }

                if (status == PermissionStatus.Granted)
                {
                    await StartTracking();
                }
                else
                {
                    await ShowDisplayPopup("Error", "Auto Dashboard requires the Location Permission (Precise) to be enabled and granted to the SFK BMS App. Additionally, Location Services must be turned on for the feature to work properly. Please grant this permission, enable Location Services, and restart the app.");
                }
            }
            catch (Exception ex)
            {
            }
        }
        private async Task StartTracking()
        {
            if (_isTrackingRunning)
            {
                return;
            }

            _isTrackingRunning = true;

            _cts = new CancellationTokenSource();

            SpeedUnitValue = Preferences.Get("SpeedUnitValue", "mph");

            timer = new PeriodicTimer(TimeSpan.FromMilliseconds(500));

            _ = Task.Run(async () =>
            {
                try
                {
                    while (await timer.WaitForNextTickAsync(_cts.Token))
                    {
                        await Timer_Elapsed();
                    }
                }
                catch (OperationCanceledException)
                {
                }
            });
        }
        private async Task StopTracking()
        {
            _isTrackingRunning = false;

            _isGPSFlashing = false;

            if (_cts != null)
            {
                _cts.Cancel();
                _cts.Dispose();
                _cts = null;
            }

            if (timer != null)
            {
                timer.Dispose();
                timer = null;
            }
        }
        private async Task Timer_Elapsed()
        {
            if (_isTimerRunning)
            {
                return;
            }

            _isTimerRunning = true;

            try
            {
                var request = new GeolocationRequest(GeolocationAccuracy.High, TimeSpan.FromSeconds(20));

                var location = await Geolocation.GetLocationAsync(request) ?? await Geolocation.GetLastKnownLocationAsync();

                if (location == null)
                {
                    return;
                }

                MainThread.BeginInvokeOnMainThread(() =>
                {
                    var accuracy = location.Accuracy ?? 1000;
                    var _Image = accuracy > 60 ? "gpsred.png" : accuracy > 30 ? "gpsorange.png" : "gpsgreen.png";

                    imgAutoGPSIcon.Source = ImageSource.FromFile(_Image);

                    if (_Image == "gpsred.png")
                    {
                        if (!_isGPSFlashing)
                        {
                            _isGPSFlashing = true;
                            _gpsFlashTask = Task.Run(async () =>
                            {
                                while (_isGPSFlashing)
                                {
                                    await MainThread.InvokeOnMainThreadAsync(() => imgAutoGPSIcon.IsVisible = false);
                                    await Task.Delay(700);
                                    await MainThread.InvokeOnMainThreadAsync(() => imgAutoGPSIcon.IsVisible = true);
                                    await Task.Delay(700);
                                }
                            });
                        }
                    }
                    else
                    {
                        _isGPSFlashing = false;
                        imgAutoGPSIcon.IsVisible = true;
                    }
                });

                double kmphSpeed = 0;

                if (location.Speed.HasValue && location.Speed > 0)
                {
                    kmphSpeed = Math.Round(location.Speed.Value * 3.6, 2);

                    _lastValidSpeed = kmphSpeed;

                    _lastSpeedTime = DateTime.Now;
                }
                else
                {
                    if (_lastValidSpeed > 0 && (DateTime.Now - _lastSpeedTime).TotalSeconds < 5)
                    {
                        kmphSpeed = _lastValidSpeed;
                    }
                }

                double SpeedValue = SpeedUnitValue == "mph" ? Math.Round(kmphSpeed * 0.621371, 2) : kmphSpeed;

                await MainThread.InvokeOnMainThreadAsync(() =>
                {
                    if (SpeedValue > 1)
                    {
                        lblAutoSpeed.TextColor = lblAutoSpeedType.TextColor = SpeedValue > 85 ? Colors.Red : SpeedValue > 40 ? Colors.Orange : Colors.Green;

                        double rounded = Math.Round(SpeedValue, 0);
                        lblAutoSpeed.Text = rounded < 10 ? $"0{rounded}" : Convert.ToString(rounded);
                    }
                    else
                    {
                        lblAutoSpeed.TextColor = lblAutoSpeedType.TextColor = Color.FromArgb("#000000");
                        lblAutoSpeed.Text = "00";
                        _lastValidSpeed = 0;
                    }
                });
            }
            catch (Exception ex)
            {
                await MainThread.InvokeOnMainThreadAsync(async () =>
                {
                    await ShowDisplayPopup("Error", "Location error: " + ex.Message);
                });
            }
            finally
            {
                _isTimerRunning = false;
            }
        }
        private async void stackUnit_Tapped(object sender, TappedEventArgs e)
        {
            try
            {
                var Unit = ((StackLayout)sender).ClassId;

                if (Unit == "mph" || Unit == "kph")
                {
                    stackkph.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblkph.TextColor = Color.FromArgb("#818181");
                    stackmph.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblmph.TextColor = Color.FromArgb("#818181");
                }
                else
                {
                    stackkW.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblkW.TextColor = Color.FromArgb("#818181");
                    stackAmp.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblAmp.TextColor = Color.FromArgb("#818181");
                    stackhp.BackgroundColor = Color.FromArgb("#FFFFFF");
                    lblhp.TextColor = Color.FromArgb("#818181");
                }

                switch (Unit)
                {
                    case "mph":
                        stackmph.BackgroundColor = Color.FromArgb("#F26D24");
                        lblmph.TextColor = Color.FromArgb("#FFFFFF");
                        lblAutoSpeedType.Text = Unit;
                        SpeedUnitValue = Unit;
                        Preferences.Set("SpeedUnitValue", Unit);
                        break;

                    case "kph":
                        stackkph.BackgroundColor = Color.FromArgb("#F26D24");
                        lblkph.TextColor = Color.FromArgb("#FFFFFF");
                        lblAutoSpeedType.Text = Unit;
                        SpeedUnitValue = Unit;
                        Preferences.Set("SpeedUnitValue", Unit);
                        break;

                    case "kW":
                        stackkW.BackgroundColor = Color.FromArgb("#008000");
                        lblkW.TextColor = Color.FromArgb("#FFFFFF");
                        lblAutoPowerType.Text = Unit;
                        PowerUnitValue = Unit;
                        Preferences.Set("PowerUnitValue", Unit);
                        break;

                    case "amp":
                        stackAmp.BackgroundColor = Color.FromArgb("#008000");
                        lblAmp.TextColor = Color.FromArgb("#FFFFFF");
                        lblAutoPowerType.Text = Unit;
                        PowerUnitValue = Unit;
                        Preferences.Set("PowerUnitValue", Unit);
                        break;

                    case "hp":
                        stackhp.BackgroundColor = Color.FromArgb("#008000");
                        lblhp.TextColor = Color.FromArgb("#FFFFFF");
                        lblAutoPowerType.Text = Unit;
                        PowerUnitValue = Unit;
                        Preferences.Set("PowerUnitValue", Unit);
                        break;
                }
            }
            catch (Exception ex)
            {
            }
        }

